static double __attribute__((noinline)) hxlcl_atof(const char *s) {
    if (!s) return 0.0;
    size_t i = 0;
    while (s[i] == ' ' || s[i] == '\t' || s[i] == '\n') i++;
    int sign = 1;
    if (s[i] == '-') { sign = -1; i++; }
    else if (s[i] == '+') i++;
    double n = 0.0;
    while (s[i] >= '0' && s[i] <= '9') {
        n = n * 10.0 + (double)(s[i] - '0');
        i++;
    }
    if (s[i] == '.') {
        i++;
        double frac = 0.1;
        while (s[i] >= '0' && s[i] <= '9') {
            n += (double)(s[i] - '0') * frac;
            frac *= 0.1;
            i++;
        }
    }
    if (s[i] == 'e' || s[i] == 'E') {
        i++;
        int esign = 1;
        if (s[i] == '-') { esign = -1; i++; }
        else if (s[i] == '+') i++;
        int exp_val = 0;
        while (s[i] >= '0' && s[i] <= '9') {
            exp_val = exp_val * 10 + (s[i] - '0');
            i++;
        }
        double mul = 1.0;
        for (int k = 0; k < exp_val; k++) mul *= 10.0;
        if (esign < 0) n /= mul;
        else n *= mul;
    }
    return (sign < 0) ? -n : n;
}
