// inline calls; ap_post.c expands them BEFORE perl substitution sees
// them. #undef + #define here unhooks any subsequent expansion to our
// hxlcl_* helpers (safe — ASCII classifiers, same locale-free intent).
#undef isalnum
#undef isalpha
#define isalnum(c) hxlcl_isalnum((int)(c))
#define isalpha(c) hxlcl_isalpha((int)(c))
// Cycle 65: exit() in <stdlib.h> as inline that calls _exit/__exit
// after libc cleanup. Override to call our exit syscall (SYS_EXIT=1)
// directly. Drops _exit + __exit externs.
#undef exit
#undef _exit
#define exit(c)  hxlcl_exit((int)(c))
#define _exit(c) hxlcl_exit((int)(c))
// Cycle 57 — Tier-A.4 POSIX stubs are NOT #define'd here because their
// system-header prototypes (signal/sigaction/socket.h declarations)
// expand the macro inside the prototype itself ("function cannot return
// function type" errors). Instead, call sites in runtime.c +
// runtime_core.c use the hxlcl_* names directly via perl substitution
// (see cycle 57 commit). The helpers above are referenced by those
// direct calls; no #define indirection needed.

/* amalgam BEGIN runtime_core.c */
// ═══════════════════════════════════════════════════════════
//  HEXA C Runtime — CORE tier (runtime_core.c)
//  RFC 061 Phase P1: 2-layer split, phase 1.
//
//  This file is the irreducible C core of the hexa runtime per the
//  RFC 061 §4.1 boundary criterion: HexaVal representation bits
//  (NaN-box tag macros, the struct/union layout), the allocator hot
//  path (arena, malloc wrappers, array/map primitive memory ops),
//  the universal codegen-emitted primitives (hexa_int/float/str/bool/
//  void constructors, hexa_add and the arithmetic/comparison family,
//  hexa_index_get, hexa_len, hexa_array_new/push/get/set, hexa_map_*),
//  and their transitive closure (string interning, branch-hint macros,
//  RSS cap, fuel telemetry — all referenced on the core path).
//
//  It is #include-d (NOT separately compiled) by self/runtime.c right
//  after the system #include block; the preprocessor concatenation of
//  runtime.c's system headers + this file + runtime.c's HI tier yields
//  a translation unit byte-identical to the pre-split runtime.c.
//
//  HI-tier functions (FFI, struct-pack, trampoline, term/exec/json/
//  regex, farr, safetensors, tensor, autograd, the ML numerics) stay
//  in runtime.c — RFC 061 P2/P3 migrate those to hexa source.
//
//  NOTE on size: a clean *contiguous-prefix* split lands the core at
//  ~6.0 k lines, larger than the RFC §5b per-function projection
//  (≈2.4-3 k). The prefix cut is deliberate — it is provably
//  zero-behavior-change (pure file partition; no function reorder, so
//  no risk to internal forward-decl / file-scope-static ordering).
//  A small number of string/math/format helpers that §5b classifies
//  HI sit in this prefix; they are exactly the P2/P3 migration
//  tranches and will leave this file when rewritten in hexa.
// ═══════════════════════════════════════════════════════════

// ═══════════════════════════════════════════════════════════
//  Branch hints + cold attribute + cacheline prefetch
//  (A17 / A18 / Z20 — docs/hexa_speedup_brainstorm_2026_05_06.ai.md)
// ═══════════════════════════════════════════════════════════
// HX_LIKELY / HX_UNLIKELY: __builtin_expect wrappers for hot-path bias.
//   Only wrap branches whose taken-direction is dominated (>~80%) by a
//   single arm in measured workloads — wrong-way hints can hurt by 1-2%.
// HX_COLD: function attribute that pushes the body into the cold .text
//   section so it doesn't pollute icache on the common path.
// HX_PREFETCH: cacheline prefetch hint (no-op on archs without builtin).
// All three are zero-cost no-ops under non-GCC/Clang compilers.
#if defined(__GNUC__) || defined(__clang__)
#  ifndef HX_LIKELY
#    define HX_LIKELY(x)   __builtin_expect(!!(x), 1)
#  endif
#  ifndef HX_UNLIKELY
#    define HX_UNLIKELY(x) __builtin_expect(!!(x), 0)
#  endif
#  ifndef HX_COLD
#    define HX_COLD __attribute__((cold))
#  endif
#  ifndef HX_PREFETCH
#    define HX_PREFETCH(addr) __builtin_prefetch((const void*)(addr), 0, 1)
#  endif
#else
#  ifndef HX_LIKELY
#    define HX_LIKELY(x)   (x)
#  endif
#  ifndef HX_UNLIKELY
#    define HX_UNLIKELY(x) (x)
#  endif
#  ifndef HX_COLD
#    define HX_COLD
#  endif
#  ifndef HX_PREFETCH
#    define HX_PREFETCH(addr) ((void)0)
#  endif
#endif

// hexa_pipe_buf_enlarge — TL;DR #4 pipe buffer optimization (2026-05-06).
// Two variants because the optimal lever differs by read pattern:
//
//   _kernel — Linux F_SETPIPE_SZ only (1 MB kernel pipe). No-op on macOS.
//             Use for fread()-based bulk drain paths (hexa_exec,
//             hexa_exec_with_status). The userland setvbuf path costs more
//             than it saves there: caller already does fread() into a 4 KB
//             stack buf, and macOS adds a 256 KB malloc + memcpy hop per
//             popen with no syscall reduction (measured 2x regression on
//             50 MB `yes | head` stream, 2026-05-06).
//
//   _full   — F_SETPIPE_SZ on Linux + setvbuf 256 KB userland on all
//             platforms. Use for fgets()-based streaming paths
//             (hexa_exec_stream_impl). Streaming reads line-at-a-time, so
//             a large refill buffer behind fgets() amortizes the syscall.
//
// Linux F_SETPIPE_SZ may be rejected (EPERM if pipe-max-size exceeded,
// EINVAL on old kernels) — silently fall back, never fail the caller.
// Must be called immediately after popen() and before any I/O on fp —
// setvbuf() requires a fresh stream.
static inline void hexa_pipe_buf_enlarge_kernel(FILE* fp) {
    if (!fp) return;
#ifdef __linux__
#ifdef F_SETPIPE_SZ
    int fd = fileno(fp);
    if (fd >= 0) {
        (void)hxlcl_fcntl(fd, F_SETPIPE_SZ, 1 << 20);
        // Ignore errno (EPERM/EINVAL) — kernel may reject; default size
        // still works correctly, only throughput differs.
    }
#endif
#else
    (void)fp;  // macOS: F_SETPIPE_SZ unsupported, leave default.
#endif
}

static inline void hexa_pipe_buf_enlarge_full(FILE* fp) {
    if (!fp) return;
    hexa_pipe_buf_enlarge_kernel(fp);
    // Userland FILE* buffer: 256 KB fully-buffered. Helps fgets() amortize
    // the read() syscall over many lines.
    (void)setvbuf(fp, NULL, _IOFBF, 256 * 1024);
}

// 2026-05-06 audit closure:
//   - stdout: _IOLBF (line-buffered) — flushes on newline when redirected to
//     file/pipe so subprocess prompts and progress aren't held mid-line.
//   - stderr: _IONBF (unbuffered) — POSIX default for stderr is unbuffered
//     so diagnostics appear immediately even on partial-line writes (e.g.
//     "loading…" without newline). Earlier _IOLBF setting was over-buffered.
//   - SIGPIPE: SIG_IGN — when a child closes its stdin while the parent is
//     mid-write (interactive prompts, build pipelines), the default SIGPIPE
//     would kill the runtime. Ignoring it lets write() return EPIPE and the
//     caller decide how to handle the broken-pipe case.
__attribute__((constructor))
static void _hexa_init_stdio(void) {
    setvbuf(stdout, NULL, _IOLBF, 0);
    setvbuf(stderr, NULL, _IONBF, 0);
    hxlcl_signal(SIGPIPE, SIG_IGN);
}

// ═══════════════════════════════════════════════════════════
//  PATH augmentation for macOS — Homebrew / MacPorts visibility
// ═══════════════════════════════════════════════════════════
//
// Background: hexa modules call exec("timeout 30 ...") / exec("python3 -c ...")
// expecting that subshells (popen → /bin/sh -c) can find binaries on the
// operator's normal PATH. On macOS, common operator tools (timeout, gtimeout,
// python3, qrencode, jq, ripgrep, ...) live under /opt/homebrew/bin (Apple
// Silicon) or /usr/local/bin (Intel + linuxbrew). When hexa is invoked from a
// context where the parent's PATH was sanitized (launchd, cron, system
// services that bypass the user shell, or any caller that exec'd hexa with a
// minimal env), popen() faithfully passes that minimal PATH through to
// /bin/sh, and "timeout" / "python3" disappear — surfacing as silent failures
// or 127 exit codes inside hexa modules.
//
// Pragmatic root-cause fix: on macOS, pre-pend the standard package-manager
// prefixes to PATH at runtime startup so every popen()/fork+exec child
// inherits a path that can resolve the operator's everyday tools. This
// matches what an interactive shell startup (zsh + /etc/zprofile + path_helper)
// would do, except we apply it inside the hexa process even when launched
// from a non-shell parent. Linux is left untouched (its FHS layout already
// has /usr/local/bin in the default PATH on most distros, and Homebrew on
// Linux installs to /home/linuxbrew/.linuxbrew/bin which the operator's
// shell rc already injects).
//
// Escape hatch:
//   HEXA_PATH_NO_AUGMENT=1   → disable; child sees parent PATH verbatim.
//
// Idempotency: each candidate is added only if not already present
// (substring match against `:`-delimited segments). Order: candidates are
// pre-pended in the order listed below, so /opt/homebrew/bin wins over
// /usr/local/bin (matches Apple Silicon Homebrew priority over linuxbrew /
// stale Intel installs).
//
// Security boundary: this changes which directories popen() searches; it
// does NOT introduce a new shell-injection vector (callers still pass a
// quoted command to popen as before). An operator who explicitly wants the
// minimal PATH (e.g. for sandbox testing) sets HEXA_PATH_NO_AUGMENT=1.
__attribute__((constructor))
static void _hexa_init_path_augment(void) {
#if defined(__APPLE__)
    const char* opt = hxlcl_getenv("HEXA_PATH_NO_AUGMENT");
    if (opt && opt[0] == '1' && opt[1] == '\0') return;

    const char* old = hxlcl_getenv("PATH");
    if (!old) old = "";

    // Candidates pre-pended in order. /opt/homebrew first (Apple Silicon
    // Homebrew default), /usr/local next (Intel Homebrew + manual installs),
    // /opt/local last (MacPorts). sbin variants included for tools like
    // pfctl wrappers shipped under sbin in some bottles.
    static const char* const candidates[] = {
        "/opt/homebrew/bin",
        "/opt/homebrew/sbin",
        "/usr/local/bin",
        "/usr/local/sbin",
        "/opt/local/bin",
        "/opt/local/sbin",
        NULL
    };

    // Build new PATH = <missing candidates joined by ':'> + ':' + old.
    // Worst-case length: sum of all candidates + separators + old + NUL.
    size_t cap = hxlcl_strlen(old) + 1;
    for (int i = 0; candidates[i]; i++) cap += hxlcl_strlen(candidates[i]) + 1;
    char* buf = (char*)malloc(cap);
    if (!buf) return;
    buf[0] = '\0';

    for (int i = 0; candidates[i]; i++) {
        const char* c = candidates[i];
        size_t clen = hxlcl_strlen(c);
        // Substring search for ":<c>:", "<c>:" (start), or ":<c>" (end), or
        // exact match. Cheap O(n*m) scan — PATH is rarely > 4 KB and this
        // runs once at process start.
        int found = 0;
        const char* p = old;
        while (*p) {
            const char* q = hxlcl_strchr(p, ':');
            size_t seg = q ? (size_t)(q - p) : hxlcl_strlen(p);
            if (seg == clen && hxlcl_memcmp(p, c, clen) == 0) { found = 1; break; }
            if (!q) break;
            p = q + 1;
        }
        if (!found) {
            hxlcl_strcat(buf, c);
            hxlcl_strcat(buf, ":");
        }
    }
    hxlcl_strcat(buf, old);

    // Only call setenv if we actually added something (buf longer than old).
    if (hxlcl_strlen(buf) > hxlcl_strlen(old)) {
        hxlcl_setenv("PATH", buf, 1);
    }
    free(buf);
#endif
}

// ═══════════════════════════════════════════════════════════
//  RSS soft cap — runtime guard against runaway memory
// ═══════════════════════════════════════════════════════════
//
// Background: macOS rejects setrlimit(RLIMIT_AS|DATA|RSS,...) with EINVAL,
// so the only effective in-process cap is polling self-RSS via task_info()
// (Darwin) or /proc/self/statm (Linux). When exceeded, we exit(77) with a
// clear stderr trailer instead of letting the process grow until jetsam
// SIGKILL or system swap pressure.
//
// Tick model: hot paths (hexa_arena_alloc / hexa_array_push / hexa_strbuf_alloc)
// call _hx_mem_tick(). Internally a counter modulo (every 2^16 calls) decides
// whether to actually syscall. Per-call overhead ≈ 1 increment + 1 mask + 1
// branch; the syscall is amortized to ~once per tens of MB of allocation.
//
// Defaults & overrides (2026-05-16 — opt-IN model):
//   default               → NO cap. A legitimate heavy compile (the
//                            compiler self-compile peaks ~30 GB) is more
//                            common than a runaway, and a spurious
//                            exit(77) kills real work — worse than
//                            letting the OS arbitrate. The cap is OFF
//                            unless explicitly asked for.
//   HEXA_MEM_LIMIT=<N>     → opt in to a cap of N MB (must be >0). The
//                            primary knob — e.g. HEXA_MEM_LIMIT=4096
//                            asserts a 4 GB ceiling for a footprint test.
//   HEXA_MEM_CAP_MB=<N>    → legacy alias of HEXA_MEM_LIMIT (still honored).
//   HEXA_MEM_UNLIMITED=1   → legacy explicit-disable; now also the default,
//                            kept so old wrappers/scripts stay valid no-ops.
//
// Pre-2026-05-16 this defaulted to a 4096 MB cap (raised over time
// 768→2048→4096 as the embedded atlas grew). That default is removed —
// callers wanting a ceiling now set HEXA_MEM_LIMIT explicitly.
//
// CLI flags (parsed by the hexa wrapper script, exported as env above):
//   --mem-limit=<N> / --mem-cap=<N> → HEXA_MEM_LIMIT / HEXA_MEM_CAP_MB
//   --mem-unlimited                 → HEXA_MEM_UNLIMITED=1 (now a no-op)

static size_t _hx_mem_cap_bytes = 4096ull * 1024ull * 1024ull;  // used only when a cap is opted in
static int    _hx_mem_cap_disabled = 1;  // 2026-05-16: NO cap by default
static volatile uint64_t _hx_mem_tick_ctr = 0;

__attribute__((constructor))
static void _hexa_init_mem_cap(void) {
    // Opt-in cap. HEXA_MEM_LIMIT is the primary knob; HEXA_MEM_CAP_MB is
    // a legacy alias. Either one, set to a positive MB value, enables the
    // cap. HEXA_MEM_UNLIMITED=1 forces it back off (and is the default).
    const char* lim = hxlcl_getenv("HEXA_MEM_LIMIT");
    if (lim && lim[0] != '\0') {
        long long mb = hxlcl_atoll(lim);
        if (mb > 0) {
            _hx_mem_cap_bytes = (size_t)mb * 1024ull * 1024ull;
            _hx_mem_cap_disabled = 0;
        }
    }
    const char* cap = hxlcl_getenv("HEXA_MEM_CAP_MB");
    if (cap && cap[0] != '\0') {
        long long mb = hxlcl_atoll(cap);
        if (mb > 0) {
            _hx_mem_cap_bytes = (size_t)mb * 1024ull * 1024ull;
            _hx_mem_cap_disabled = 0;
        }
    }
    const char* unl = hxlcl_getenv("HEXA_MEM_UNLIMITED");
    if (unl && unl[0] == '1' && unl[1] == '\0') {
        _hx_mem_cap_disabled = 1;
    }
}

static size_t _hx_self_rss_bytes(void) {
#if defined(__APPLE__)
    mach_task_basic_info_data_t info;
    mach_msg_type_number_t cnt = MACH_TASK_BASIC_INFO_COUNT;
    if (hxlcl_task_info(mach_task_self(), MACH_TASK_BASIC_INFO,
                  (task_info_t)&info, &cnt) != KERN_SUCCESS) return 0;
    return (size_t)info.resident_size;
#elif defined(__linux__)
    FILE* f = fopen("/proc/self/statm", "r");
    if (!f) return 0;
    long pages_total = 0, pages_rss = 0;
    if (fscanf(f, "%ld %ld", &pages_total, &pages_rss) != 2) {
        fclose(f); return 0;
    }
    fclose(f);
    long ps = sysconf(_SC_PAGESIZE);
    if (ps <= 0) ps = 4096;
    return (size_t)pages_rss * (size_t)ps;
#else
    return 0;
#endif
}

// ═══════════════════════════════════════════════════════════
//  Fuel-abort telemetry emitter — atlas/anima ledger pipeline
//  hxa-2026-05-06 fuel_abort_telemetry stub (worker fuel-emit-pipeline)
//
//  Schema: hexa-lang/runtime_fuel_abort/1
//  Target: $HEXA_LANG/state/hx_runtime_fuel_abort.jsonl  (append-only JSONL)
//
//  Triggered from any abort path (mem-cap; future cpu/wall fuel exhaustion).
//  Payload: ts, kind ("mem"|"cpu"|"wall"|"oom"), exit_code, binary path,
//           argv[1..N], rss_mb, cap_mb, fuel_count, top_frame,
//           rusage (utime_us+stime_us+maxrss_kb).
//  Best-effort: any failure (state dir missing, fd starvation) is silently
//  swallowed — never let telemetry break an abort path.
//
//  TODO(fuel-worker): when interpreter fuel lands, call _hx_emit_fuel_abort
//  from interpreter.hexa abort site too (kind="cpu" / "wall"); pass
//  top_frame string (function name + line) once interp exposes it.
//  TODO(fuel-worker): switch to atomic O_APPEND + flock for safe parallel
//  AOT processes hitting the cap simultaneously.
// ═══════════════════════════════════════════════════════════

// Forward-decl globals (defined ~line 4632) so the emitter can read argv.
static int _hexa_argc;
static char** _hexa_argv;

// JSON-escape into caller's buffer; returns bytes written (excl. NUL).
// Truncates at cap-1 to guarantee NUL term. Bounded so we don't allocate.
static size_t _hx_fuel_json_esc(char* dst, size_t cap, const char* s) {
    if (!dst || cap == 0) return 0;
    size_t out = 0;
    if (!s) { dst[0] = '\0'; return 0; }
    for (; *s && out + 2 < cap; s++) {
        unsigned char c = (unsigned char)*s;
        if (c == '\\' || c == '"') {
            if (out + 3 >= cap) break;
            dst[out++] = '\\';
            dst[out++] = (char)c;
        } else if (c == '\n') {
            if (out + 3 >= cap) break;
            dst[out++] = '\\'; dst[out++] = 'n';
        } else if (c == '\r') {
            if (out + 3 >= cap) break;
            dst[out++] = '\\'; dst[out++] = 'r';
        } else if (c == '\t') {
            if (out + 3 >= cap) break;
            dst[out++] = '\\'; dst[out++] = 't';
        } else if (c < 0x20) {
            if (out + 7 >= cap) break;
            int n = snprintf(dst + out, cap - out, "\\u%04x", c);
            if (n <= 0) break;
            out += (size_t)n;
        } else {
            dst[out++] = (char)c;
        }
    }
    dst[out] = '\0';
    return out;
}

// Public entry. kind ∈ {"mem","cpu","wall","oom"}. Best-effort emit.
// Non-static so future Hexa-side callers (interp fuel) can FFI it via
// the existing dlsym pathway; meanwhile internal callers use it directly.
void _hx_emit_fuel_abort(const char* kind,
                         int exit_code,
                         long long fuel_count,
                         size_t rss_bytes,
                         size_t cap_bytes,
                         const char* top_frame) {
    if (!kind) kind = "unknown";
    if (!top_frame) top_frame = "";

    // Resolve ledger path. Honor HEXA_FUEL_LEDGER override (tests / dry-run);
    // fall back to $HEXA_LANG/state/, then $HOME/core/hexa-lang/state/.
    char path[1024];
    const char* override_p = hxlcl_getenv("HEXA_FUEL_LEDGER");
    if (override_p && override_p[0]) {
        snprintf(path, sizeof(path), "%s", override_p);
    } else {
        const char* root = hxlcl_getenv("HEXA_LANG");
        if (!root || !root[0]) {
            const char* home = hxlcl_getenv("HOME");
            if (!home || !home[0]) home = "/tmp";
            snprintf(path, sizeof(path),
                     "%s/core/hexa-lang/state/hx_runtime_fuel_abort.jsonl", home);
        } else {
            snprintf(path, sizeof(path),
                     "%s/state/hx_runtime_fuel_abort.jsonl", root);
        }
    }

    // ISO-8601 UTC timestamp (no exec; format inline).
    char ts[32];
    time_t now = hxlcl_time(NULL);
    struct tm tmv;
#if defined(_WIN32)
    gmtime_s(&tmv, &now);
#else
    gmtime_r(&now, &tmv);
#endif
    hxlcl_strftime(ts, sizeof(ts), "%Y-%m-%dT%H:%M:%SZ", &tmv);

    // RUSAGE snapshot (best-effort; on failure leave zeros).
    long utime_us = 0, stime_us = 0, maxrss_kb = 0;
    struct rusage ru;
    if (hxlcl_getrusage(RUSAGE_SELF, &ru) == 0) {
        utime_us = (long)ru.ru_utime.tv_sec * 1000000L + (long)ru.ru_utime.tv_usec;
        stime_us = (long)ru.ru_stime.tv_sec * 1000000L + (long)ru.ru_stime.tv_usec;
        // ru_maxrss: Linux=KB, macOS=bytes. Normalize to KB.
        maxrss_kb = (long)ru.ru_maxrss;
#if defined(__APPLE__)
        maxrss_kb /= 1024L;
#endif
    }

    // Binary path = argv[0]; user args = argv[2..argc-1] (argv[1] is dup of argv[0]).
    const char* binary = (_hexa_argv && _hexa_argc > 0) ? _hexa_argv[0] : "";
    if (!binary) binary = "";

    // Build args array string: ["a","b",...]
    char args_buf[1024];
    args_buf[0] = '['; args_buf[1] = '\0';
    size_t apos = 1;
    int args_start = (_hexa_argc >= 2) ? 2 : _hexa_argc;
    int wrote = 0;
    for (int i = args_start; i < _hexa_argc && _hexa_argv && _hexa_argv[i]; i++) {
        if (apos + 4 >= sizeof(args_buf)) break;
        if (wrote) { args_buf[apos++] = ','; }
        args_buf[apos++] = '"';
        char esc[256];
        _hx_fuel_json_esc(esc, sizeof(esc), _hexa_argv[i]);
        size_t elen = hxlcl_strlen(esc);
        if (apos + elen + 2 >= sizeof(args_buf)) { apos--; break; }
        hxlcl_memcpy(args_buf + apos, esc, elen); apos += elen;
        args_buf[apos++] = '"';
        wrote = 1;
    }
    if (apos + 1 < sizeof(args_buf)) args_buf[apos++] = ']';
    args_buf[apos] = '\0';

    // JSON-escape variable strings.
    char binary_esc[512];
    char top_esc[256];
    char kind_esc[32];
    _hx_fuel_json_esc(binary_esc, sizeof(binary_esc), binary);
    _hx_fuel_json_esc(top_esc, sizeof(top_esc), top_frame);
    _hx_fuel_json_esc(kind_esc, sizeof(kind_esc), kind);

    // Compose the JSONL line.
    char line[3072];
    int n = snprintf(line, sizeof(line),
        "{\"schema\":\"hexa-lang/runtime_fuel_abort/1\""
        ",\"ts\":\"%s\""
        ",\"event\":\"hexa.runtime.fuel_abort\""
        ",\"kind\":\"%s\""
        ",\"exit_code\":%d"
        ",\"binary\":\"%s\""
        ",\"args\":%s"
        ",\"fuel_count\":%lld"
        ",\"rss_mb\":%llu"
        ",\"cap_mb\":%llu"
        ",\"top_frame\":\"%s\""
        ",\"rusage\":{\"utime_us\":%ld,\"stime_us\":%ld,\"maxrss_kb\":%ld}"
        "}\n",
        ts, kind_esc, exit_code, binary_esc, args_buf,
        fuel_count,
        (unsigned long long)(rss_bytes / (1024ull * 1024ull)),
        (unsigned long long)(cap_bytes / (1024ull * 1024ull)),
        top_esc,
        utime_us, stime_us, maxrss_kb);
    if (n <= 0) return;
    if ((size_t)n >= sizeof(line)) n = (int)sizeof(line) - 1;

    // Best-effort mkdir of immediate parent dir; silent on failure.
    {
        char dir[1024];
        size_t pl = hxlcl_strlen(path);
        size_t cut = pl;
        while (cut > 0 && path[cut - 1] != '/') cut--;
        if (cut > 0 && cut < sizeof(dir)) {
            hxlcl_memcpy(dir, path, cut - 1);
            dir[cut - 1] = '\0';
            // TODO(fuel-worker): full mkdir -p chain. state/ usually exists.
            (void)mkdir(dir, 0755);
        }
    }

    FILE* f = fopen(path, "a");
    if (!f) {
        // Last-resort: stderr trailer so external watchers still see it.
        fprintf(stderr, "[hexa-runtime/fuel_abort] %s", line);
        return;
    }
    fwrite(line, 1, (size_t)n, f);
    fflush(f);
    fclose(f);
}

__attribute__((noinline))
static void _hx_mem_cap_fire(size_t rss) {
    fprintf(stderr,
        "[hexa-runtime] memory cap exceeded: rss=%zuMB > cap=%zuMB\n"
        "[hexa-runtime] hint: this cap is opt-in (HEXA_MEM_LIMIT/HEXA_MEM_CAP_MB) — "
        "raise HEXA_MEM_LIMIT=<MB>, or unset it for no cap (the default).\n",
        (size_t)(rss / (1024ull*1024ull)),
        (size_t)(_hx_mem_cap_bytes / (1024ull*1024ull)));
    // Telemetry: ledger emit before exit. Best-effort; never blocks the abort.
    // fuel_count = -1 (n/a for memory cap; future interp fuel passes int).
    _hx_emit_fuel_abort("mem", 77, -1, rss, _hx_mem_cap_bytes, "");
    exit(77);
}

static inline void _hx_mem_tick(void) {
    if (_hx_mem_cap_disabled) return;
    // 2026-05-05: 0xFFFF (65 536 calls) → 0x0FFF (4 096 calls) — 16× more
    // frequent. Tightens overshoot bound on bursty allocators (the
    // observed runaways went 1 → 5 GB inside one 30s watcher window).
    if ((++_hx_mem_tick_ctr & 0x0FFFu) != 0) return;
    size_t rss = _hx_self_rss_bytes();
    if (rss > _hx_mem_cap_bytes) _hx_mem_cap_fire(rss);
}

// ── H03 (2026-05-06): forward decls for HEXA_ALLOC_STATS extensions ──
// Storage + main definitions live alongside the rt 32 stats block (~line 1080+).
// We declare them up-front so early callers (hexa_intern, hexa_closure_new,
// hexa_fn_new — all defined before the stats block) can reference them.
// `_hx_stats_on()` is the central guard; everything else is only touched
// inside that guard, so unset-env paths are a single predicted branch + RET.
static int _hx_stats_on(void);
#define HX_POOL_LRU 8
static int64_t _hx_stats_intern_hit;     // file-scope tentative defs (zero-init)
static int64_t _hx_stats_intern_miss;
static int64_t _hx_stats_intern_skip;
static int64_t _hx_stats_intern_grow;
static int64_t _hx_stats_closure_alloc;
static int64_t _hx_stats_fn_alloc;
static int64_t _hx_stats_fn_alloc_dup;
static int64_t _hx_stats_clo_alloc_dup;
static void* _hx_stats_fn_lru[HX_POOL_LRU];
static void* _hx_stats_clo_lru[HX_POOL_LRU];
static int   _hx_stats_fn_lru_pos;
static int   _hx_stats_clo_lru_pos;
static inline int _hx_stats_lru_check(void** ring, int* pos, void* p) {
    for (int i = 0; i < HX_POOL_LRU; i++) {
        if (ring[i] == p) return 1;
    }
    ring[*pos] = p;
    *pos = (*pos + 1) % HX_POOL_LRU;
    return 0;
}

// ═══════════════════════════════════════════════════════════
//  Optimization #11: String Interning
//  Hash-set of unique strings. Short strings (< 64 chars)
//  are interned; comparison becomes pointer equality (==).
//  Lazily initialized on first hexa_intern() call.
// ═══════════════════════════════════════════════════════════

#define INTERN_INIT_CAP   1024
#define INTERN_MAX_LEN    64
#define INTERN_LOAD_MAX   75   // percent

static uint32_t hexa_fnv1a(const char* s, size_t len) {
    uint32_t h = 2166136261u;
    for (size_t i = 0; i < len; i++) {
        h ^= (uint8_t)s[i];
        h *= 16777619u;
    }
    return h;
}

// Also used by the hash-map (#10)
uint32_t hexa_fnv1a_str(const char* s) {
    uint32_t h = 2166136261u;
    for (; *s; s++) {
        h ^= (uint8_t)*s;
        h *= 16777619u;
    }
    return h;
}

typedef struct {
    char** buckets;      // array of interned string pointers (NULL = empty)
    uint32_t* hashes;    // cached hash per slot
    int cap;             // power-of-2 capacity
    int count;           // number of occupied slots
} HexaInternTable;

static HexaInternTable __hexa_intern = {NULL, NULL, 0, 0};

static void hexa_intern_init(void) {
    __hexa_intern.cap = INTERN_INIT_CAP;
    __hexa_intern.count = 0;
    __hexa_intern.buckets = (char**)calloc(INTERN_INIT_CAP, sizeof(char*));
    __hexa_intern.hashes  = (uint32_t*)calloc(INTERN_INIT_CAP, sizeof(uint32_t));
}

static void hexa_intern_grow(void) {
    int old_cap = __hexa_intern.cap;
    char** old_buckets = __hexa_intern.buckets;
    uint32_t* old_hashes = __hexa_intern.hashes;
    int new_cap = old_cap * 2;
    char** new_buckets = (char**)calloc(new_cap, sizeof(char*));
    uint32_t* new_hashes = (uint32_t*)calloc(new_cap, sizeof(uint32_t));
    uint32_t mask = (uint32_t)(new_cap - 1);
    for (int i = 0; i < old_cap; i++) {
        if (old_buckets[i]) {
            uint32_t idx = old_hashes[i] & mask;
            while (new_buckets[idx]) idx = (idx + 1) & mask;
            new_buckets[idx] = old_buckets[i];
            new_hashes[idx] = old_hashes[i];
        }
    }
    free(old_buckets);
    free(old_hashes);
    __hexa_intern.buckets = new_buckets;
    __hexa_intern.hashes  = new_hashes;
    __hexa_intern.cap = new_cap;
}

// ═══════════════════════════════════════════════════════════
//  String length-header (perf-31, 2026-04-26)
//
//  Embed an 8-byte size_t length immediately before each owned
//  string buffer. HX_STR(v) still returns the data pointer (no
//  caller change), but HX_STRLEN(v) reads the cached length in
//  O(1) — eliminating the per-call strlen() that turned every
//  hot string fn (substring, char_at, replace, …) into O(n²).
//
//  Magic-byte guard lets HX_STRLEN safely fall back to strlen()
//  when called with a pointer that did NOT come from a header
//  allocator (e.g. arena-allocated map keys at runtime.c:1364
//  which can't reasonably grow a header — those are short type
//  names where strlen is cheap anyway).
// ═══════════════════════════════════════════════════════════

#define HEXA_STR_MAGIC ((uint64_t)0xC0DECAFE0F58A7E1ULL)

typedef struct {
    uint64_t magic;
    size_t   len;
    char     data[];   // C99 flexible array — actual bytes follow
} HexaStrHdr;

// Allocate a string buffer with embedded length header. Returns the
// data pointer (caller stores in HexaVal.s); the header sits at
// (data - sizeof(HexaStrHdr)). data[len] is pre-NUL-terminated so
// callers can fill bytes 0..len-1 and immediately treat as C string.
static inline char* hexa_strbuf_alloc(size_t len) {
    _hx_mem_tick();
    HexaStrHdr* hdr = (HexaStrHdr*)malloc(sizeof(HexaStrHdr) + len + 1);
    if (!hdr) return NULL;
    hdr->magic = HEXA_STR_MAGIC;
    hdr->len = len;
    hdr->data[len] = '\0';
    return hdr->data;
}

// Allocate header buffer + memcpy from src. src may be NULL when len==0.
static inline char* hexa_strbuf_dup_n(const char* src, size_t len) {
    char* buf = hexa_strbuf_alloc(len);
    if (!buf) return NULL;
    if (len > 0 && src) hxlcl_memcpy(buf, src, len);
    return buf;
}

// O(1) length read. Reads 16 bytes before s and matches HEXA_STR_MAGIC
// to confirm header presence; falls back to strlen otherwise. Reading
// before s is safe in practice because every code path that puts a
// pointer into HexaVal.s uses heap-allocated memory (malloc / strdup /
// arena_alloc), all of which sit on heap chunks with ≥16 bytes of
// allocator metadata in front, so the load won't fault.
static inline size_t hexa_strlen_v_inline(const char* s) {
    if (!s) return 0;
    // sizeof(struct{...; char data[]}) == offset of flex array → header size
    HexaStrHdr* hdr = (HexaStrHdr*)((const char*)s - sizeof(HexaStrHdr));
    if (hdr->magic == HEXA_STR_MAGIC) return hdr->len;
    return hxlcl_strlen(s);
}

#define HX_STRLEN(v)    hexa_strlen_v_inline(HX_STR(v))
#define HX_STRLEN_S(s)  hexa_strlen_v_inline(s)

// Intern a string: returns a canonical pointer.
// If the string is already interned, returns the existing pointer.
// Only interns strings shorter than INTERN_MAX_LEN.
// The returned pointer is owned by the intern table -- callers must NOT free it.
static const char* hexa_intern(const char* s) {
    if (HX_UNLIKELY(!s)) return s;
    size_t slen = hxlcl_strlen(s);
    if (HX_UNLIKELY(slen >= INTERN_MAX_LEN)) {
        // H03 Q9: count strings rejected by length cap.
        if (_hx_stats_on()) _hx_stats_intern_skip++;
        return NULL;  // too long, skip interning
    }

    // Lazy init — fires once per process; everything after is hot-path.
    if (HX_UNLIKELY(!__hexa_intern.buckets)) hexa_intern_init();

    uint32_t h = hexa_fnv1a(s, slen);
    uint32_t mask = (uint32_t)(__hexa_intern.cap - 1);
    uint32_t idx = h & mask;

    // A17: most workloads exhibit a heavy hit-rate (>90%) on hexa_intern —
    // self-hosting parser interns identifiers + keywords repeatedly. Hint
    // the slot-occupied loop and the hash-equal+strcmp-hit branch as taken.
    while (HX_LIKELY(__hexa_intern.buckets[idx] != NULL)) {
        if (HX_LIKELY(__hexa_intern.hashes[idx] == h) &&
            hxlcl_strcmp(__hexa_intern.buckets[idx], s) == 0) {
            // H03 Q9: hit — table contained an equal canonical pointer.
            if (_hx_stats_on()) _hx_stats_intern_hit++;
            return __hexa_intern.buckets[idx];  // already interned
        }
        idx = (idx + 1) & mask;
    }

    // Not found -- insert (header-allocated so HX_STRLEN works on interned strings)
    // Grow path is rare (amortised O(log N) over program lifetime).
    if (HX_UNLIKELY(__hexa_intern.count * 100 / __hexa_intern.cap >= INTERN_LOAD_MAX)) {
        hexa_intern_grow();
        if (_hx_stats_on()) _hx_stats_intern_grow++;
        // Recompute slot after grow
        mask = (uint32_t)(__hexa_intern.cap - 1);
        idx = h & mask;
        while (__hexa_intern.buckets[idx]) idx = (idx + 1) & mask;
    }

    char* dup = hexa_strbuf_dup_n(s, slen);
    __hexa_intern.buckets[idx] = dup;
    __hexa_intern.hashes[idx]  = h;
    __hexa_intern.count++;
    if (_hx_stats_on()) _hx_stats_intern_miss++;
    return dup;
}

