// ── to_string ────────────────────────────────────────────

// 2026-04-20 container-repr fix: TAG_ARRAY/TAG_MAP branches added so
// `str(arr)` / `str(map)` produce readable `[e1, e2]` / `{k: v, ...}`
// output instead of the "<value>" fallback. Mirrors hexa_print_val
// (runtime.c:2796) which already handled TAG_ARRAY — the asymmetry
// between hexa_print_val (direct print) and hexa_to_string (string
// concat via `+`) was surfacing as `"arr=" + str(arr) -> "arr=<value>"`.
// Guards: recursion depth cap (8) to prevent stack blow-up on cyclic
// references; element cap (64) so a 1M-element tensor-as-array does
// not allocate a multi-MB string; null pointer guards on arr_ptr /
// map_ptr / order_keys before deref (T33 arena-dangling defence).
static HexaVal _hexa_to_string_rec(HexaVal v, int depth);

// Step-4 cycle 96 port — scalar branches (int [outside cache] / float
// [integer-valued in range] / bool / void / str) dispatch to hexa source.
// Small-int cache + non-integer float [%g] + array/map/valstruct stay C.
#ifdef HEXA_HAS_HEXA_RT_STDLIB
extern HexaVal rt_to_string_scalar(HexaVal v);
HexaVal hexa_to_string(HexaVal v) {
    /* Array/Map/ValStruct: recursive C body. */
    if (HX_IS_VALSTRUCT(v) || HX_TAG(v) == TAG_ARRAY || HX_TAG(v) == TAG_MAP) {
        return _hexa_to_string_rec(v, 0);
    }
    /* Small-int cache fast path. */
    if (HX_IS_INT(v) &&
        HX_INT(v) >= SMALL_INT_CACHE_MIN &&
        HX_INT(v) <= SMALL_INT_CACHE_MAX) {
        if (!_cached_small_ints_ready) _hexa_init_small_int_cache();
        return _cached_small_ints[HX_INT(v) - SMALL_INT_CACHE_MIN];
    }
    /* Non-integer-valued float: env-honoring fmt (default %g, opt-in g15/g17
     * via HEXA_FLOAT_REPR — matches print_val path).  PROBE r11 B6.
     * PROBE r14-E: pre-empt NaN/inf with Rust canonical casing. */
    if (HX_IS_FLOAT(v)) {
        double f = HX_FLOAT(v);
        const char* sp = __hexa_float_special_repr(f);
        if (sp) return hexa_str(sp);
        if (!(isfinite(f) && f == floor(f) && f >= -1e15 && f <= 1e15)) {
            char buf[64];
            snprintf(buf, 64, __hexa_print_float_fmt(), f);
            return hexa_str(buf);
        }
    }
    return rt_to_string_scalar(v);
}
#else
HexaVal hexa_to_string(HexaVal v) {
    return _hexa_to_string_rec(v, 0);
}
#endif

static HexaVal _hexa_to_string_rec(HexaVal v, int depth) {
    if (!_cached_strs_ready) _hexa_init_cached_strs();
    char buf[64];
    switch (HX_TAG(v)) {
        case TAG_INT: {
            // ROI-33: small-int cache hit — skip snprintf+intern entirely
            if (HX_INT(v) >= SMALL_INT_CACHE_MIN && HX_INT(v) <= SMALL_INT_CACHE_MAX) {
                if (!_cached_small_ints_ready) _hexa_init_small_int_cache();
                return _cached_small_ints[HX_INT(v) - SMALL_INT_CACHE_MIN];
            }
            snprintf(buf, 64, "%lld", (long long)HX_INT(v));
            return hexa_str(buf);
        }
        case TAG_FLOAT: {
            // trk.27 fix 2026-05-06: preserve `.0` for whole-valued floats so
            // to_string(0.0) returns "0.0" not "0", matching python json.dumps
            // and existing test assertions (test_lang_core.hexa:141 +
            // test_type_coercion.hexa:35 — to_string(3.0) == "3.0"). Plain %g
            // strips trailing zeros — use %.1f when float is integer-valued +
            // finite + within int-representable range; env-honoring fmt
            // (default %g, opt-in g15/g17 via HEXA_FLOAT_REPR) otherwise.
            // PROBE r11 B6.
            // PROBE r14-E (2026-05-23): pre-empt NaN/inf with Rust canonical
            // casing ("NaN"/"inf"/"-inf") before falling through to %g/%.1f
            // (libc default is lowercase "nan"/"inf").
            double f = HX_FLOAT(v);
            const char* sp = __hexa_float_special_repr(f);
            if (sp) return hexa_str(sp);
            if (isfinite(f) && f == floor(f) && f >= -1e15 && f <= 1e15) {
                snprintf(buf, 64, "%.1f", f);
            } else {
                snprintf(buf, 64, __hexa_print_float_fmt(), f);
            }
            return hexa_str(buf);
        }
        case TAG_BOOL: return HX_BOOL(v) ? _cached_str_true : _cached_str_false;
        case TAG_STR: return v;
        case TAG_VOID: return _cached_str_void;
        // rt 32-G: minimal fallback repr — interpreter has its own
        // val_to_string for the full form.
        // Step 4 cycle 97 — minimal-repr port (잔여 #8). C wrapper retains
        // the HX_VS NULL guard + `<Val null>` sentinel; hexa source emits
        // the `Val{tag=N,i=M}` body via existing .get() builtin which
        // routes through hexa_valstruct_get_by_key at runtime (no new
        // codegen builtin required).
        case TAG_VALSTRUCT: {
            if (!HX_VS(v)) return hexa_str("<Val null>");
#ifdef HEXA_HAS_HEXA_RT_STDLIB
            extern HexaVal rt_valstruct_repr(HexaVal v);
            return rt_valstruct_repr(v);
#else
            snprintf(buf, 64, "Val{tag=%lld,i=%lld}",
                (long long)HX_VSF(v, tag_i), (long long)HX_VSF(v, int_val));
            return hexa_str(buf);
#endif
        }
        case TAG_ARRAY: {
            if (depth >= 8) return hexa_str("[...]");
            if (!v.arr_ptr) return hexa_str("[<null>]");
#ifdef HEXA_HAS_HEXA_RT_STDLIB
            // Step 5 #3 cycle C2-retry — array container render ports to
            // hexa source. NULL-ptr + depth guards stay C; rt_to_string_array
            // owns the element loop / cap / overflow-trailer; nested
            // arrays/maps recurse in hexa, scalars dispatch to hexa_to_string.
            extern HexaVal rt_to_string_array(HexaVal arr, HexaVal depth);
            return rt_to_string_array(v, hexa_int(depth));
#else
            int n = HX_ARR_LEN(v);
            int cap = 64;  // element-dump cap
            HexaVal out = hexa_str("[");
            HexaVal sep = hexa_str(", ");
            int shown = n < cap ? n : cap;
            for (int i = 0; i < shown; i++) {
                if (i > 0) out = hexa_str_concat(out, sep);
                out = hexa_str_concat(out, _hexa_to_string_rec(HX_ARR_ITEMS(v)[i], depth + 1));
            }
            if (n > cap) {
                snprintf(buf, 64, ", ... (%d more)", n - cap);
                out = hexa_str_concat(out, hexa_str(buf));
            }
            out = hexa_str_concat(out, hexa_str("]"));
            return out;
#endif
        }
        case TAG_MAP: {
            if (depth >= 8) return hexa_str("{...}");
            HexaMapTable* t = HX_MAP_TBL(v);
            if (!t) return hexa_str("{}");
#ifdef HEXA_HAS_HEXA_RT_STDLIB
            // Step 5 #3 cycle C2-retry — map container render ports to hexa
            // source. NULL-tbl + depth guards stay C; rt_to_string_map owns
            // the key/value loop.
            extern HexaVal rt_to_string_map(HexaVal m, HexaVal depth);
            return rt_to_string_map(v, hexa_int(depth));
#else
            int n = t->len;
            int cap = 64;
            HexaVal out = hexa_str("{");
            HexaVal sep = hexa_str(", ");
            HexaVal kv_sep = hexa_str(": ");
            int shown = n < cap ? n : cap;
            for (int i = 0; i < shown; i++) {
                if (i > 0) out = hexa_str_concat(out, sep);
                const char* k = (t->order_keys && t->order_keys[i]) ? t->order_keys[i] : "<null>";
                out = hexa_str_concat(out, hexa_str(k));
                out = hexa_str_concat(out, kv_sep);
                out = hexa_str_concat(out, _hexa_to_string_rec(t->order_vals[i], depth + 1));
            }
            if (n > cap) {
                snprintf(buf, 64, ", ... (%d more)", n - cap);
                out = hexa_str_concat(out, hexa_str(buf));
            }
            out = hexa_str_concat(out, hexa_str("}"));
            return out;
#endif
        }
        default: return _cached_str_value;
    }
}

// ── Truthy check ─────────────────────────────────────────

int hexa_truthy(HexaVal v) {
    switch (HX_TAG(v)) {
        case TAG_BOOL: return HX_BOOL(v);
        case TAG_INT: return HX_INT(v) != 0;
        // 2026-04-20 silent-fallback audit: TAG_FLOAT was falling through
        // to `default: return 1`, so `if 0.0 { ... }` evaluated truthy.
        // Match TAG_INT semantics — zero is falsy. NaN is truthy (non-zero).
        case TAG_FLOAT: return HX_FLOAT(v) != 0.0;
        case TAG_STR: return HX_STR(v) != NULL && HX_STR(v)[0] != 0;
        case TAG_VOID: return 0;
        // rt 32-G: TAG_VALSTRUCT truthy iff .vs pointer non-null.
        case TAG_VALSTRUCT: return HX_VS(v) != NULL;
        default: return 1;
    }
}

// ── Type checking ────────────────────────────────────────

HexaVal hexa_type_of(HexaVal v) {
    if (!_cached_strs_ready) _hexa_init_cached_strs();
    switch (HX_TAG(v)) {
        case TAG_INT: return _cached_str_int;
        case TAG_FLOAT: return _cached_str_float;
        case TAG_BOOL: return _cached_str_bool;
        case TAG_STR: return _cached_str_string;
        case TAG_VOID: return _cached_str_void;
        case TAG_ARRAY: return _cached_str_array;
        case TAG_MAP: return _cached_str_map;
        // 2026-04-20 silent-fallback audit: prior default dropped TAG_FN /
        // TAG_CHAR / TAG_CLOSURE into "unknown" — Hexa-side dispatch like
        // `type_of(x) != "string"` then misclassified callable values.
        // Surface them explicitly; any remaining unknown tag is a real bug.
        case TAG_FN: return _cached_str_fn;
        case TAG_CHAR: return _cached_str_char;
        case TAG_CLOSURE: return _cached_str_closure;
        // rt 32-G: Val is a struct at the Hexa level; surface "struct".
        case TAG_VALSTRUCT: return _cached_str_struct;
        default: return _cached_str_unknown;
    }
}

// ── Polymorphic add (int + or string concat) ─────────────

// ROI-37: rename impl to _slow so the macro below can inline the int+int
// fast path without function-call ABI overhead.
/* PHASE 1.2.B (2026-05-15): de-staticized. Slow-path fallback for the
 * hexa_add macro emitted into runtime.h — user.c TUs link against this. */
HexaVal hexa_add_slow(HexaVal a, HexaVal b) {
    // Bool → int coercion (Python canonical: True=1, False=0).  Without this,
    // `true + 1` fell through to `hexa_to_string + str_concat` → "true1".
    // Round-7 probe finding.
    if (HX_IS_BOOL(a)) a = hexa_int(HX_BOOL(a) ? 1 : 0);
    if (HX_IS_BOOL(b)) b = hexa_int(HX_BOOL(b) ? 1 : 0);
    if (HX_IS_INT(a) && HX_IS_INT(b)) return hexa_int(HX_INT(a) + HX_INT(b));
    if (HX_IS_FLOAT(a) || HX_IS_FLOAT(b)) {
        // T39: unwrap via __hx_to_double so TAG_VALSTRUCT wrappers don't
        // cast the vs pointer to double (same root as T32 to_float bug).
        double fa = __hx_to_double(a);
        double fb = __hx_to_double(b);
        return hexa_float(fa + fb);
    }
    // B13: array concat. Interpreter (hexa_full.hexa:6954) does this but
    // codegen emits bare hexa_add(l,r) — without this branch, two arrays
    // fall through to to_string+str_concat → TAG_STR, then later arr[i]
    // reads .arr.len from a TAG_STR union slot (stack residue → random OOB).
    if (HX_IS_ARRAY(a) && HX_IS_ARRAY(b)) {
        HexaVal out = hexa_array_new();
        for (int i = 0; i < HX_ARR_LEN(a); i++) out = hexa_array_push(out, HX_ARR_ITEMS(a)[i]);
        for (int i = 0; i < HX_ARR_LEN(b); i++) out = hexa_array_push(out, HX_ARR_ITEMS(b)[i]);
        return out;
    }
    HexaVal sa = hexa_to_string(a);
    HexaVal sb = hexa_to_string(b);
    return hexa_str_concat(sa, sb);
}

// ROI-37: inline macro — int+int hot path avoids 32-byte HexaVal call ABI.
// Evaluates each operand exactly once via temporaries.
#define hexa_add(A, B) \
    ({ HexaVal __ha = (A), __hb = (B); \
       (HX_IS_INT(__ha) && HX_IS_INT(__hb)) \
           ? hexa_int(HX_INT(__ha) + HX_INT(__hb)) \
           : hexa_add_slow(__ha, __hb); })

// ── Variadic concat (N-way) — clang bracket-depth relief ─────
// codegen flattens long `+` chains (≥16 operands) into a single call:
//   hexa_concat_many(N, (HexaVal[]){e1, e2, ..., eN})
// instead of hexa_add(hexa_add(hexa_add(...))) which blows past clang's
// default 256-level bracket nesting limit on anima launcher files
// (launch_alm_14b_r9.hexa ~170 deep → fatal). Semantics = left-fold via
// hexa_add so mixed int/string/array inputs follow the same rules as the
// pairwise operator.
#ifndef HEXA_HAS_HEXA_RT_STDLIB
HexaVal hexa_concat_many(int n, HexaVal* parts) {
    if (n <= 0) return hexa_str("");
    HexaVal acc = parts[0];
    for (int i = 1; i < n; i++) {
        acc = hexa_add(acc, parts[i]);
    }
    return acc;
}
#else
// Step-3 cycle 89 — hexa-source port via TAG_ARRAY bridge. The variadic
// `HexaVal*` C buffer can't be expressed in hexa source (잔여 #7), so
// we wrap it in a TAG_ARRAY HexaVal (one hexa_array_new + n pushes) and
// delegate to rt_concat_many_arr. Semantics are byte-identical to the C
// body (left-fold `acc = acc + parts[i]` lowers to `hexa_add(acc,
// parts[i])` since `acc` is `let mut` untyped). Owner of the loop:
// stdlib/runtime/numeric.hexa::rt_concat_many_arr.
extern HexaVal rt_concat_many_arr(HexaVal parts);
HexaVal hexa_concat_many(int n, HexaVal* parts) {
    if (n <= 0) return hexa_str("");
    HexaVal arr = hexa_array_new();
    for (int i = 0; i < n; i++) {
        arr = hexa_array_push(arr, parts[i]);
    }
    return rt_concat_many_arr(arr);
}
#endif

// ── Polymorphic equality ─────────────────────────────────

/* Step 3 cycle 100 — pointer-eq inline builtins for hexa_eq TAG_VALSTRUCT
 * + TAG_MAP branches (RUNTIME.md 잔여 #4, 4 of 9 branches ported). The
 * aprime_cc codegen inlines `__vs_ptr_eq(a,b)` / `__map_ptr_eq(a,b)` to
 * `hexa_bool(HX_VS(a)==HX_VS(b))` etc. The hexa_v2 bootstrap transpiler
 * is unaware of the inline lowering and emits
 * `hexa_call2(__vs_ptr_eq, a, b)`; the static-inline defs below satisfy
 * that indirect-call path via the `hexa_call2` _Generic dispatch on
 * `HexaVal (*)(HexaVal, HexaVal)`. Either way the lowered compare is
 * byte-identical to the legacy C body. Mirror lives in self/runtime.h
 * for non-aprime build paths. */
#ifndef __vs_ptr_eq_DEFINED
#define __vs_ptr_eq_DEFINED
static inline HexaVal __vs_ptr_eq(HexaVal a, HexaVal b) {
    return hexa_bool((HX_VS(a)) == (HX_VS(b)));
}
#endif
#ifndef __map_ptr_eq_DEFINED
#define __map_ptr_eq_DEFINED
static inline HexaVal __map_ptr_eq(HexaVal a, HexaVal b) {
    return hexa_bool((HX_MAP_TBL(a)) == (HX_MAP_TBL(b)));
}
#endif

HexaVal hexa_eq(HexaVal a, HexaVal b) {
    // Cross-type numeric equality (int ↔ float) — matches interp
    // eval_binop float-coerce path (hexa_full.hexa:7867). 이전엔
    // tag 불일치 즉시 false → `2 == 2.0` AOT=false / interp=true
    // divergence 를 유발.
    if (HX_IS_INT(a) && HX_IS_FLOAT(b)) return hexa_bool((double)HX_INT(a) == HX_FLOAT(b));
    if (HX_IS_FLOAT(a) && HX_IS_INT(b)) return hexa_bool(HX_FLOAT(a) == (double)HX_INT(b));
    if (HX_TAG(a) != HX_TAG(b)) return hexa_bool(0);
    switch (HX_TAG(a)) {
#ifdef HEXA_HAS_HEXA_RT_STDLIB
        /* Step-3 cycle 103 — same-tag scalar branches ported to hexa
           source (RUNTIME.md 잔여 #4 → 9/9 candidate branches). Both
           operands are guaranteed the same scalar tag here (cross-type
           numeric coercion + HX_TAG(a)==HX_TAG(b) guard already passed).
           rt_eq_int/float express equality via ordered comparisons
           (hexa_cmp_le/ge — NOT redirected, byte-exact incl. NaN);
           rt_eq_bool avoids comparison on HexaVals entirely. None lower
           to a hexa_eq call site, so no recursion (transpile-verified). */
        case TAG_INT: {
            extern HexaVal rt_eq_int(HexaVal a, HexaVal b);
            return hexa_bool(hexa_truthy(rt_eq_int(a, b)));
        }
        case TAG_FLOAT: {
            extern HexaVal rt_eq_float(HexaVal a, HexaVal b);
            return hexa_bool(hexa_truthy(rt_eq_float(a, b)));
        }
        case TAG_BOOL: {
            extern HexaVal rt_eq_bool(HexaVal a, HexaVal b);
            return hexa_bool(hexa_truthy(rt_eq_bool(a, b)));
        }
#else
        case TAG_INT: return hexa_bool(HX_INT(a) == HX_INT(b));
        case TAG_FLOAT: return hexa_bool(HX_FLOAT(a) == HX_FLOAT(b));
        case TAG_BOOL: return hexa_bool(HX_BOOL(a) == HX_BOOL(b));
#endif
        case TAG_STR: {
            /* Intern fast-path stays C (HX_STR pointer identity). */
            if (HX_STR(a) == HX_STR(b)) return hexa_bool(1);
#ifdef HEXA_HAS_HEXA_RT_STDLIB
            /* Step-3 cycle 91 — strcmp fallback via cycle-57 rt_str_eq_b. */
            extern HexaVal rt_str_eq_b(HexaVal a, HexaVal b);
            return hexa_bool(hexa_truthy(rt_str_eq_b(a, b)));
#else
            return hexa_bool(hxlcl_strcmp(HX_STR(a), HX_STR(b)) == 0);
#endif
        }
        case TAG_VOID: return hexa_bool(1);
        // rt 32-G: Val identity is pointer-equality of heap struct (matches
        // TAG_MAP semantics — two separately constructed maps never compare
        // equal by value).
        case TAG_VALSTRUCT: {
#ifdef HEXA_HAS_HEXA_RT_STDLIB
            /* Step-3 cycle 100 — hexa-source port via __vs_ptr_eq inline
               builtin. The hexa body is a single `return __vs_ptr_eq(a, b)`,
               so the lowered C is a single `HX_VS(a) == HX_VS(b)` compare —
               byte-equivalent to the legacy path. RUNTIME.md 잔여 #4
               (3 of 9 branches now ported). */
            extern HexaVal rt_eq_valstruct(HexaVal a, HexaVal b);
            return hexa_bool(hexa_truthy(rt_eq_valstruct(a, b)));
#else
            return hexa_bool(HX_VS(a) == HX_VS(b));
#endif
        }
        // Array deep equality — interp eval_binop (hexa_full.hexa:7939) 가
        // 요소별 vals_equal 로 비교하므로 AOT 도 요소 재귀 비교로 정렬.
        // 이전 comment 는 interp 가 ref eq 이라고 기록했지만 실제 코드는
        // value eq. 같은 포인터 shortcut 으로 빠른 경로 유지.
        case TAG_ARRAY: {
            /* Same-ptr fast-path + length check stay C (cheap). */
            if (a.arr_ptr == b.arr_ptr) return hexa_bool(1);
            int __na = HX_ARR_LEN(a); int __nb = HX_ARR_LEN(b);
            if (__na != __nb) return hexa_bool(0);
#ifdef HEXA_HAS_HEXA_RT_STDLIB
            /* Step-3 cycle 97 — element-by-element deep loop via
               rt_eq_array_deep (hexa source). Inside the ported fn,
               `a[i] != b[i]` re-enters hexa_eq for each pair; scalar
               cases stay C, nested arrays recurse back into this
               case → rt_eq_array_deep. Mutual recursion on a strictly
               smaller subtree, so well-formed input terminates. */
            extern HexaVal rt_eq_array_deep(HexaVal a, HexaVal b);
            return hexa_bool(hexa_truthy(rt_eq_array_deep(a, b)));
#else
            HexaVal* __xa = HX_ARR_ITEMS(a); HexaVal* __xb = HX_ARR_ITEMS(b);
            for (int __i = 0; __i < __na; __i++) {
                if (!hexa_truthy(hexa_eq(__xa[__i], __xb[__i]))) return hexa_bool(0);
            }
            return hexa_bool(1);
#endif
        }
        case TAG_MAP: {
#ifdef HEXA_HAS_HEXA_RT_STDLIB
            /* Step-3 cycle 100 — hexa-source pointer-eq fast-path via
               __map_ptr_eq inline builtin (RUNTIME.md 잔여 #4, 4 of 9
               branches now ported). Hexa body is `return __map_ptr_eq(a, b)`
               which lowers to the same `HX_MAP_TBL(a) == HX_MAP_TBL(b)`
               compare. The `__tag` enum-variant deep-compare below stays
               C-side (separate logic, future cycle). */
            extern HexaVal rt_eq_map_ptr(HexaVal a, HexaVal b);
            if (hexa_truthy(rt_eq_map_ptr(a, b))) return hexa_bool(1);
#else
            if (HX_MAP_TBL(a) == HX_MAP_TBL(b)) return hexa_bool(1);
#endif
            // #28 — enum value equality. The native (aprime_cc) lowering
            // represents an enum variant as a map { "__tag": hash, "__pN": … }
            // (compiler/lower/hir_to_mir.hexa enum_path → struct_lit). Two
            // separately constructed enum maps for the same variant must
            // compare equal, mirroring the match-arm `__tag` discriminant
            // test. Plain maps / structs ("__type__"-keyed, or no marker)
            // keep pointer-identity semantics — unchanged. Scoped strictly
            // to "__tag"-bearing maps so struct / dict `==` is untouched.
            if (hexa_map_contains_key(a, "__tag") && hexa_map_contains_key(b, "__tag")) {
                HexaVal ta = hexa_map_get(a, "__tag");
                HexaVal tb = hexa_map_get(b, "__tag");
                if (!hexa_truthy(hexa_eq(ta, tb))) return hexa_bool(0);
                // Same variant ⇒ same payload arity. Compare each "__pN"
                // payload structurally until the first absent slot.
                for (int __pi = 0; ; __pi++) {
                    char __pk[24];
                    snprintf(__pk, sizeof(__pk), "__p%d", __pi);
                    int ha = hexa_map_contains_key(a, __pk);
                    int hb = hexa_map_contains_key(b, __pk);
                    if (!ha && !hb) break;
                    if (ha != hb) return hexa_bool(0);
                    if (!hexa_truthy(hexa_eq(hexa_map_get(a, __pk),
                                             hexa_map_get(b, __pk))))
                        return hexa_bool(0);
                }
                return hexa_bool(1);
            }
            return hexa_bool(0);
        }
        // TAG_FN: compare underlying C function pointer (descriptor indirection
        // may differ for two separately-constructed wrappers of the same fn).
        case TAG_FN:
            return hexa_bool(
                (a.fn_ptr_d && b.fn_ptr_d)
                    ? (HX_FN_PTR(a) == HX_FN_PTR(b))
                    : (a.fn_ptr_d == b.fn_ptr_d));
        case TAG_CHAR: return hexa_bool(HX_INT(a) == HX_INT(b));
        case TAG_CLOSURE:
            return hexa_bool(
                (a.clo_ptr && b.clo_ptr)
                    ? (HX_CLO_PTR(a) == HX_CLO_PTR(b))
                    : (a.clo_ptr == b.clo_ptr));
        default: return hexa_bool(0);
    }
}

// ── File I/O ─────────────────────────────────────────────

// ─────────────────────────────────────────────────────────────────────
// M1 full · file layer (hxa-20260423-003 Step 3)
// rt_file_* hand-port — authoritative implementations for file I/O.
// hexa_* wrappers below are shims forwarding to rt_* (preserves external
// ABI: self/bootstrap_compiler.c, build_c.hexa emit, codegen emit).
// ─────────────────────────────────────────────────────────────────────

HexaVal rt_read_file(HexaVal path) {
    FILE* f = fopen(HX_STR(path), "rb");
    if (!f) return hexa_str("");
    fseek(f, 0, SEEK_END);
    long len = ftell(f);
    fseek(f, 0, SEEK_SET);
    char* buf = malloc(len + 1);
    fread(buf, 1, len, f);
    buf[len] = 0;
    fclose(f);
    return hexa_str_own(buf);
}

HexaVal rt_write_file(HexaVal path, HexaVal content) {
    FILE* f = fopen(HX_STR(path), "wb");
    if (!f) return hexa_bool(0);
    const char* s = HX_STR(content);
    size_t len = s ? hxlcl_strlen(s) : 0;
    fwrite(s, 1, len, f);
    fclose(f);
    return hexa_bool(1);
}

// P7-6 builtin (2026-04-18): boolean existence probe. Used by native_build
// and other self-hosting scripts to gate optional inputs without a
// full read_file round-trip.
//
// ω-stdlib-2 (2026-04-26): refined to S_ISREG semantics, matching the
// portable_fs.hexa POSIX-wc contract that consumers were forced to alias
// around (pfs_file_exists). Previously used access(p, F_OK) which returns
// true for ANY path entry incl. directories / symlinks-to-dirs / sockets.
// Now: stat() + S_ISREG → true only for regular files. Null/missing/non-
// regular → false. No errno propagation.
HexaVal rt_file_exists(HexaVal path) {
    const char* p = HX_STR(path);
    if (!p) return hexa_bool(0);
    struct stat st;
    if (hxlcl_stat(p, &st) != 0) return hexa_bool(0);
    return hexa_bool(S_ISREG(st.st_mode) ? 1 : 0);
}

// ── Binary file I/O — write_bytes / read_file_bytes ─────
// write_bytes: takes a path and a TAG_ARRAY of integers (0-255),
// writes raw bytes. Null bytes survive — true binary I/O.
HexaVal rt_write_bytes(HexaVal path, HexaVal arr) {
    if (!HX_IS_ARRAY(arr)) return hexa_bool(0);
    int len = HX_ARR_LEN(arr);
    FILE* f = fopen(HX_STR(path), "wb");
    if (!f) return hexa_bool(0);
    if (len > 0) {
        unsigned char* buf = (unsigned char*)malloc(len);
        HexaVal* items = HX_ARR_ITEMS(arr);
        for (int i = 0; i < len; i++) {
            int64_t v = HX_IS_INT(items[i]) ? HX_INT(items[i]) : (int64_t)HX_FLOAT(items[i]);
            buf[i] = (unsigned char)(v & 0xFF);
        }
        fwrite(buf, 1, len, f);
        free(buf);
    }
    fclose(f);
    return hexa_bool(1);
}

// rt_write_bytes_v: variant called from the interpreter dispatch where each
// array item is a TAG_VALSTRUCT (Val) rather than a raw HexaVal int. Reads
// the inner `int_val` field from each Val and writes the low byte. Without
// this, write_bytes from interpreted user code silently no-ops (HX_IS_INT
// fails on TAG_VALSTRUCT items) or — with the historical fputs path — UTF-8
// encodes each byte > 0x7F to two bytes. (2026-04-17)
HexaVal rt_write_bytes_v(HexaVal path, HexaVal arr) {
    if (!HX_IS_ARRAY(arr)) return hexa_bool(0);
    int len = HX_ARR_LEN(arr);
    FILE* f = fopen(HX_STR(path), "wb");
    if (!f) return hexa_bool(0);
    if (len > 0) {
        unsigned char* buf = (unsigned char*)malloc(len);
        HexaVal* items = HX_ARR_ITEMS(arr);
        for (int i = 0; i < len; i++) {
            HexaVal item = items[i];
            int64_t v = 0;
            if (HX_IS_INT(item)) {
                v = HX_INT(item);
            } else if (HX_TAG(item) == TAG_FLOAT) {
                v = (int64_t)HX_FLOAT(item);
            } else if (HX_TAG(item) == TAG_VALSTRUCT) {
                HexaVal iv = hexa_valstruct_int(item);
                if (HX_IS_INT(iv)) {
                    v = HX_INT(iv);
                } else if (HX_TAG(iv) == TAG_FLOAT) {
                    v = (int64_t)HX_FLOAT(iv);
                }
            }
            buf[i] = (unsigned char)(v & 0xFF);
        }
        fwrite(buf, 1, len, f);
        free(buf);
    }
    fclose(f);
    return hexa_bool(1);
}

// read_file_bytes: reads a file in binary mode and returns
// a TAG_ARRAY of integers (0-255), one per byte.
HexaVal rt_read_file_bytes(HexaVal path) {
    FILE* f = fopen(HX_STR(path), "rb");
    if (!f) return hexa_array_new();
    fseek(f, 0, SEEK_END);
    long len = ftell(f);
    fseek(f, 0, SEEK_SET);
    unsigned char* buf = (unsigned char*)malloc(len);
    fread(buf, 1, len, f);
    fclose(f);
    // Pre-allocate array with exact capacity
    HexaVal arr = hexa_array_new();
    if (len > 0) {
        HX_SET_ARR_ITEMS(arr, (HexaVal*)malloc(sizeof(HexaVal) * len));
        HX_SET_ARR_CAP(arr, (int)len);
        HX_SET_ARR_LEN(arr, (int)len);
        HexaVal* items = HX_ARR_ITEMS(arr);
        for (long i = 0; i < len; i++) {
            items[i] = hexa_int((int64_t)buf[i]);
        }
    }
    free(buf);
    return arr;
}

// ── P4 streaming builtins — read_bytes_at / write_bytes_append ─────
// Required for multi-GB safetensors→hexaw conversion on 14B Qwen2.5
// (8 shards × ~3.7GB each). Whole-file read_file_bytes cannot fit.

// read_bytes_at(path, offset, nbytes): pread-style ranged read.
// Returns a TAG_ARRAY of at most `nbytes` ints (shorter if EOF reached
// or offset is past EOF). Empty array on fopen failure.
HexaVal rt_read_bytes_at(HexaVal path, HexaVal offset, HexaVal nbytes) {
    int64_t off = HX_IS_INT(offset) ? HX_INT(offset)
                : (HX_TAG(offset) == TAG_FLOAT ? (int64_t)HX_FLOAT(offset) : 0);
    int64_t req = HX_IS_INT(nbytes) ? HX_INT(nbytes)
                : (HX_TAG(nbytes) == TAG_FLOAT ? (int64_t)HX_FLOAT(nbytes) : 0);
    if (off < 0 || req <= 0) return hexa_array_new();
    FILE* f = fopen(HX_STR(path), "rb");
    if (!f) return hexa_array_new();
    // Use 64-bit seek where available; on macOS/Linux fseeko is standard.
#if defined(_WIN32)
    if (_fseeki64(f, (long long)off, SEEK_SET) != 0) { fclose(f); return hexa_array_new(); }
#else
    if (fseeko(f, (off_t)off, SEEK_SET) != 0) { fclose(f); return hexa_array_new(); }
#endif
    unsigned char* buf = (unsigned char*)malloc((size_t)req);
    size_t got = fread(buf, 1, (size_t)req, f);
    fclose(f);
    HexaVal arr = hexa_array_new();
    if (got > 0) {
        HX_SET_ARR_ITEMS(arr, (HexaVal*)malloc(sizeof(HexaVal) * got));
        HX_SET_ARR_CAP(arr, (int)got);
        HX_SET_ARR_LEN(arr, (int)got);
        HexaVal* items = HX_ARR_ITEMS(arr);
        for (size_t i = 0; i < got; i++) {
            items[i] = hexa_int((int64_t)buf[i]);
        }
    }
    free(buf);
    return arr;
}

// write_bytes_append(path, arr): append raw bytes from an int array
// to `path` (fopen "ab"), creating the file if needed. Returns bool.
// Mirrors rt_write_bytes (raw HexaVal int array path).
HexaVal rt_write_bytes_append(HexaVal path, HexaVal arr) {
    if (!HX_IS_ARRAY(arr)) return hexa_bool(0);
    int len = HX_ARR_LEN(arr);
    FILE* f = fopen(HX_STR(path), "ab");
    if (!f) return hexa_bool(0);
    if (len > 0) {
        unsigned char* buf = (unsigned char*)malloc(len);
        HexaVal* items = HX_ARR_ITEMS(arr);
        for (int i = 0; i < len; i++) {
            int64_t v = HX_IS_INT(items[i]) ? HX_INT(items[i]) : (int64_t)HX_FLOAT(items[i]);
            buf[i] = (unsigned char)(v & 0xFF);
        }
        fwrite(buf, 1, len, f);
        free(buf);
    }
    fclose(f);
    return hexa_bool(1);
}

// write_bytes_append_v(path, arr): variant for the interpreter dispatch
// where each array item is a TAG_VALSTRUCT (Val). Mirrors write_bytes_v.
HexaVal rt_write_bytes_append_v(HexaVal path, HexaVal arr) {
    if (!HX_IS_ARRAY(arr)) return hexa_bool(0);
    int len = HX_ARR_LEN(arr);
    FILE* f = fopen(HX_STR(path), "ab");
    if (!f) return hexa_bool(0);
    if (len > 0) {
        unsigned char* buf = (unsigned char*)malloc(len);
        HexaVal* items = HX_ARR_ITEMS(arr);
        for (int i = 0; i < len; i++) {
            HexaVal item = items[i];
            int64_t v = 0;
            if (HX_IS_INT(item)) {
                v = HX_INT(item);
            } else if (HX_TAG(item) == TAG_FLOAT) {
                v = (int64_t)HX_FLOAT(item);
            } else if (HX_TAG(item) == TAG_VALSTRUCT) {
                HexaVal iv = hexa_valstruct_int(item);
                if (HX_IS_INT(iv)) {
                    v = HX_INT(iv);
                } else if (HX_TAG(iv) == TAG_FLOAT) {
                    v = (int64_t)HX_FLOAT(iv);
                }
            }
            buf[i] = (unsigned char)(v & 0xFF);
        }
        fwrite(buf, 1, len, f);
        free(buf);
    }
    fclose(f);
    return hexa_bool(1);
}

// file_size(path): native 64-bit file size without loading contents.
// Existing hexa_full dispatch read the whole file to count length — not
// viable for multi-GB safetensors shards.
//
// ω-stdlib-2 (2026-04-26): switched from fopen+fseeko/ftello to stat()
// for two reasons: (1) avoids opening the file at all — pure metadata
// query, no FD pressure, no platform-dependent fopen-on-directory
// behaviour; (2) aligns the missing-file convention with portable_fs.hexa
// (`pfs_file_size`, POSIX `wc -c`-based) which returns 0 for missing
// rather than -1. Consumers can now stop maintaining the pfs_* alias
// shadow layer. Directories / non-regular files also return 0 (size is
// only meaningful for regular files; callers needing dir-size must walk).
HexaVal rt_file_size(HexaVal path) {
    const char* p = HX_STR(path);
    if (!p) return hexa_int(0);
    struct stat st;
    if (hxlcl_stat(p, &st) != 0) return hexa_int(0);
    if (!S_ISREG(st.st_mode)) return hexa_int(0);
    return hexa_int((int64_t)st.st_size);
}

// ── Command line arguments ───────────────────────────

static int _hexa_argc = 0;
static char** _hexa_argv = NULL;

void hexa_set_args(int argc, char** argv) {
    // S1-D2: init TAG_FN shim globals before user code touches them.
    _hexa_init_fn_shims();
    // RFC 062 (2026-05-19): argv stored verbatim — no argv[0] duplication.
    // The historical double-insert ([exec, exec, sub, ...]) existed only to
    // match the tree-walking interpreter's ["hexa", "script", args...] index
    // layout. R7 retired the interpreter, so args() is now the clean
    // [exec, user-args...] layout. See RFC 062 / ROADMAP self-host child 65.
    _hexa_argc = argc;
    _hexa_argv = (char**)malloc(sizeof(char*) * (argc > 0 ? argc : 1));
    for (int i = 0; i < argc; i++) {
        _hexa_argv[i] = argv[i];
    }
}

HexaVal hexa_args() {
    HexaVal arr = hexa_array_new();
    for (int i = 0; i < _hexa_argc; i++) {
        arr = hexa_array_push(arr, hexa_str(_hexa_argv[i]));
    }
    return arr;
}

// Canonical argv API (roadmap 65 / M3, anima hxa-20260423-003 §3 M3).
// RFC 062 (argv[0] dedup) flipped args() to the clean [exec, user...]
// layout, so these helpers index from 1 (exec at 0, user args at 1..).
// script_path() = the thing that was launched, real_args() = user
// arguments only, identical across AOT/stage0.
HexaVal hexa_script_path() {
    // RFC 062: post-dedup layout — argv[0] is the launched executable.
    if (_hexa_argc < 1 || _hexa_argv[0] == NULL) return hexa_str("");
    return hexa_str(_hexa_argv[0]);
}

HexaVal hexa_real_args() {
    // RFC 062: post-dedup layout [exec, user-args...] — user args start at
    // index 1 (was 2 under the doubled [exec, exec, ...] layout). The
    // returned list is unchanged across the dedup.
    HexaVal arr = hexa_array_new();
    int start = (_hexa_argc >= 1) ? 1 : _hexa_argc;
    for (int i = start; i < _hexa_argc; i++) {
        arr = hexa_array_push(arr, hexa_str(_hexa_argv[i]));
    }
    return arr;
}

// ── Float operations ─────────────────────────────────

#include <math.h>

// T39: math helpers route through __hx_to_double so TAG_VALSTRUCT
// wrappers (interpreter Vals) don't cast vs pointer bits to double.
#ifndef HEXA_HAS_HEXA_RT_STDLIB
HexaVal hexa_sqrt(HexaVal v) {
    return hexa_float(sqrt(__hx_to_double(v)));
}
#else
extern HexaVal rt_sqrt(HexaVal v);
HexaVal hexa_sqrt(HexaVal v) {
    return rt_sqrt(hexa_float(__hx_to_double(v)));
}
#endif

#ifndef HEXA_HAS_HEXA_RT_STDLIB
HexaVal hexa_pow(HexaVal base, HexaVal exp) {
    // Integer fast-path: int^int with non-negative exponent stays int
    if (HX_IS_INT(base) && HX_IS_INT(exp) && HX_INT(exp) >= 0) {
        int64_t b = HX_INT(base), e = HX_INT(exp), r = 1;
        while (e > 0) { if (e & 1) r *= b; b *= b; e >>= 1; }
        return hexa_int(r);
    }
    return hexa_float(pow(__hx_to_double(base), __hx_to_double(exp)));
}
#else
extern HexaVal rt_pow_int(HexaVal b, HexaVal e);
extern HexaVal rt_pow_float(HexaVal b, HexaVal e);
HexaVal hexa_pow(HexaVal base, HexaVal exp) {
    if (HX_IS_INT(base) && HX_IS_INT(exp) && HX_INT(exp) >= 0) {
        return rt_pow_int(base, exp);
    }
    return rt_pow_float(hexa_float(__hx_to_double(base)),
                        hexa_float(__hx_to_double(exp)));
}
#endif

// Step 3 cycle 2 — hexa_floor/ceil/u_floor delegate to hexa-source.
#ifndef HEXA_HAS_HEXA_RT_STDLIB
HexaVal hexa_floor(HexaVal v) {
    return hexa_int((int64_t)floor(__hx_to_double(v)));
}
HexaVal hexa_u_floor(HexaVal a, HexaVal b) {
    int64_t ai = HX_IS_INT(a) ? HX_INT(a) : (int64_t)__hx_to_double(a);
    int64_t bi = HX_IS_INT(b) ? HX_INT(b) : (int64_t)__hx_to_double(b);
    if (bi == 0) return hexa_int(0);
    int64_t q = ai / bi;
    int64_t r = ai % bi;
    if (r != 0 && ((ai < 0) != (bi < 0))) q -= 1;
    return hexa_int(q);
}
HexaVal hexa_ceil(HexaVal v) {
    return hexa_int((int64_t)ceil(__hx_to_double(v)));
}
#else
extern HexaVal rt_floor(HexaVal v);
extern HexaVal rt_ceil(HexaVal v);
extern HexaVal rt_u_floor(HexaVal a, HexaVal b);
HexaVal hexa_floor(HexaVal v) {
    return rt_floor(hexa_float(__hx_to_double(v)));
}
HexaVal hexa_ceil(HexaVal v) {
    return rt_ceil(hexa_float(__hx_to_double(v)));
}
HexaVal hexa_u_floor(HexaVal a, HexaVal b) {
    int64_t ai = HX_IS_INT(a) ? HX_INT(a) : (int64_t)__hx_to_double(a);
    int64_t bi = HX_IS_INT(b) ? HX_INT(b) : (int64_t)__hx_to_double(b);
    return rt_u_floor(hexa_int(ai), hexa_int(bi));
}
#endif

// RUNTIME.md step-3 cycle 1 POC — first HI-tier hexa-source delegation
// from runtime_core.c. Source of truth: stdlib/runtime/numeric.hexa
// (rt_abs_int + rt_abs_float). #ifndef guard mirrors step-2 pattern:
// standalone build keeps C body; ap_post.c gets HEXA_HAS_HEXA_RT_STDLIB
// → hexa-emitted bodies win as strong symbols.
#ifndef HEXA_HAS_HEXA_RT_STDLIB
HexaVal hexa_abs(HexaVal v) {
    if (HX_IS_INT(v)) return hexa_int(HX_INT(v) < 0 ? -HX_INT(v) : HX_INT(v));
    return hexa_float(fabs(HX_FLOAT(v)));
}
#else
extern HexaVal rt_abs_int(HexaVal v);
extern HexaVal rt_abs_float(HexaVal v);
HexaVal hexa_abs(HexaVal v) {
    if (HX_IS_INT(v)) return rt_abs_int(v);
    return rt_abs_float(v);
}
#endif

// P7-6 math coverage (2026-04-19): transcendentals + rounding + conversions
// used by training/inference codegen. All route through __hx_to_double to
// unwrap TAG_VALSTRUCT wrappers (same pattern as hexa_sqrt).

HexaVal hexa_sin(HexaVal v)   { return hexa_float(hxlcl_sin(__hx_to_double(v))); }
HexaVal hexa_cos(HexaVal v)   { return hexa_float(hxlcl_cos(__hx_to_double(v))); }
#ifndef HEXA_HAS_HEXA_RT_STDLIB
HexaVal hexa_tan(HexaVal v)   { return hexa_float(tan(__hx_to_double(v))); }
#else
extern HexaVal rt_tan(HexaVal x);
HexaVal hexa_tan(HexaVal v)   { return rt_tan(hexa_float(__hx_to_double(v))); }
#endif
HexaVal hexa_exp(HexaVal v)   { return hexa_float(hxlcl_exp(__hx_to_double(v))); }
HexaVal hexa_log(HexaVal v)   { return hexa_float(hxlcl_log(__hx_to_double(v))); }
#ifndef HEXA_HAS_HEXA_RT_STDLIB
HexaVal hexa_log10(HexaVal v) { return hexa_float(log10(__hx_to_double(v))); }
#else
extern HexaVal rt_log10(HexaVal x);
HexaVal hexa_log10(HexaVal v) { return rt_log10(hexa_float(__hx_to_double(v))); }
#endif
#ifndef HEXA_HAS_HEXA_RT_STDLIB
HexaVal hexa_round(HexaVal v) { return hexa_int((int64_t)llround(__hx_to_double(v))); }
#else
extern HexaVal rt_round(HexaVal v);
HexaVal hexa_round(HexaVal v) { return rt_round(hexa_float(__hx_to_double(v))); }
#endif
#ifndef HEXA_HAS_HEXA_RT_STDLIB
HexaVal hexa_tanh(HexaVal v)  { return hexa_float(tanh(__hx_to_double(v))); }
#else
extern HexaVal rt_tanh(HexaVal x);
HexaVal hexa_tanh(HexaVal v)  { return rt_tanh(hexa_float(__hx_to_double(v))); }
#endif
#ifndef HEXA_HAS_HEXA_RT_STDLIB
HexaVal hexa_log2(HexaVal v)  { return hexa_float(log2(__hx_to_double(v))); }
#else
extern HexaVal rt_log2(HexaVal x);
HexaVal hexa_log2(HexaVal v)  { return rt_log2(hexa_float(__hx_to_double(v))); }
#endif

// to_float: coerce any scalar to float. Step-3 cycle 13 port.
#ifndef HEXA_HAS_HEXA_RT_STDLIB
HexaVal hexa_to_float(HexaVal v) {
    return hexa_float(__hx_to_double(v));
}
#else
extern HexaVal rt_to_float(HexaVal v);
HexaVal hexa_to_float(HexaVal v) {
    return rt_to_float(hexa_float(__hx_to_double(v)));
}
#endif

// to_int: coerce any scalar to int (truncate toward zero for floats)
HexaVal hexa_to_int(HexaVal v) {
    if (HX_IS_INT(v)) return v;
    if (HX_IS_FLOAT(v)) return hexa_int((int64_t)HX_FLOAT(v));
    // String → int fallback via existing parser
    if (HX_IS_STR(v)) return hexa_str_parse_int(v);
    return hexa_int((int64_t)__hx_to_double(v));
}

// ── String format ────────────────────────────────────

// Multi-arg format: hexa_format_n(fmt, args_array)
// Step-3 cycle 62 port — single-arg `{}` substitution dispatches to
// rt_format. The polymorphic `hexa_to_string(arg)` coercion stays
// C-side; the hexa fn receives both args as string.
#ifndef HEXA_HAS_HEXA_RT_STDLIB
HexaVal hexa_format(HexaVal fmt, HexaVal arg) {
    // Delegate to multi-arg path so brace-escape (`{{` → `{`,
    // `}}` → `}`) works uniformly in both single- and multi-arg
    // formats.  The prior strstr-based path silently emitted
    // `{{}}` literally instead of `{}`.
    if (!HX_IS_STR(fmt)) return fmt;
    HexaVal args = hexa_array_new();
    args = hexa_array_push(args, arg);
    return hexa_format_n(fmt, args);
}
#else
extern HexaVal rt_format(HexaVal fmt, HexaVal sarg);
HexaVal hexa_format(HexaVal fmt, HexaVal arg) {
    if (!HX_IS_STR(fmt)) return fmt;
    HexaVal sarg = hexa_to_string(arg);
    return rt_format(fmt, sarg);
}
#endif

HexaVal hexa_format_n(HexaVal fmt, HexaVal args) {
    // Multi-arg: replace {} and {:.N} with successive args
    if (!HX_IS_STR(fmt) || !HX_IS_ARRAY(args)) return fmt;
    size_t cap = HX_STRLEN(fmt) * 4 + HX_ARR_LEN(args) * 64 + 256;
    char* result = malloc(cap);
    size_t total = 0;
    result[0] = 0;
    char* src = HX_STR(fmt);
    int ai = 0;
    while (*src) {
        // Brace escape — `{{` emits `{`, `}}` emits `}`.  Without this
        // a Rust-style format string `"{{}}"` produced `{{}}` literal
        // instead of `{}`.  Round-5 string-format probe finding.
        if (src[0] == '{' && src[1] == '{') {
            while (total + 2 > cap) { cap *= 2; result = realloc(result, cap); }
            result[total++] = '{';
            result[total] = 0;
            src += 2;
            continue;
        }
        if (src[0] == '}' && src[1] == '}') {
            while (total + 2 > cap) { cap *= 2; result = realloc(result, cap); }
            result[total++] = '}';
            result[total] = 0;
            src += 2;
            continue;
        }
        if (src[0] == '{' && ai < HX_ARR_LEN(args)) {
            // Find closing }
            char* close = hxlcl_strchr(src, '}');
            if (close) {
                int speclen = (int)(close - src - 1);
                char spec[32] = {0};
                if (speclen > 0 && speclen < 31) hxlcl_memcpy(spec, src+1, speclen);
                char buf[128];
                HexaVal arg = HX_ARR_ITEMS(args)[ai++];
                if (spec[0] == ':' && spec[1] == '.') {
                    // Precision format {:.N} or {:.Nf}
                    int prec = hxlcl_atoi(spec + 2);
                    double val = HX_IS_FLOAT(arg) ? HX_FLOAT(arg) : (double)HX_INT(arg);
                    snprintf(buf, sizeof(buf), "%.*f", prec, val);
                } else if (spec[0] == ':') {
                    // Width/pad/int-suffix format: {:N} {:<N} {:>N} {:0N} {:Nd}
                    // Strategy: render arg via hexa_to_string, then pad/truncate
                    // to a width parsed from the spec body.
                    const char* p = spec + 1;
                    char align = 'R';                           // numeric default
                    char fill  = ' ';
                    if (*p == '<') { align = 'L'; p++; }
                    else if (*p == '>') { align = 'R'; p++; }
                    else if (*p == '^') { align = 'C'; p++; }
                    if (*p == '0' && p[1] != 0) { fill = '0'; p++; }
                    int width = 0;
                    while (*p >= '0' && *p <= '9') { width = width * 10 + (*p - '0'); p++; }
                    // ignore trailing type char ('d'/'s'/'f')
                    HexaVal s = hexa_to_string(arg);
                    int slen = (int)HX_STRLEN(s);
                    int pad = width > slen ? width - slen : 0;
                    int bp = 0;
                    if (align == 'L') {
                        hxlcl_memcpy(buf + bp, HX_STR(s), slen); bp += slen;
                        for (int q = 0; q < pad && bp < (int)sizeof(buf) - 1; q++) buf[bp++] = fill;
                    } else if (align == 'C') {
                        int lp = pad / 2, rp = pad - lp;
                        for (int q = 0; q < lp && bp < (int)sizeof(buf) - 1; q++) buf[bp++] = fill;
                        hxlcl_memcpy(buf + bp, HX_STR(s), slen); bp += slen;
                        for (int q = 0; q < rp && bp < (int)sizeof(buf) - 1; q++) buf[bp++] = fill;
                    } else {
                        for (int q = 0; q < pad && bp < (int)sizeof(buf) - 1; q++) buf[bp++] = fill;
                        hxlcl_memcpy(buf + bp, HX_STR(s), slen); bp += slen;
                    }
                    if (bp >= (int)sizeof(buf)) bp = sizeof(buf) - 1;
                    buf[bp] = 0;
                } else if (spec[0] == 0) {
                    // Simple {}
                    HexaVal s = hexa_to_string(arg);
                    hxlcl_strncpy(buf, HX_STR(s), sizeof(buf)-1); buf[sizeof(buf)-1]=0;
                } else {
                    // Indexed {N} — best-effort; non-numeric falls through to to_string
                    HexaVal s = hexa_to_string(arg);
                    hxlcl_strncpy(buf, HX_STR(s), sizeof(buf)-1); buf[sizeof(buf)-1]=0;
                }
                size_t blen = hxlcl_strlen(buf);
                while (total + blen + 1 > cap) { cap *= 2; result = realloc(result, cap); }
                hxlcl_memcpy(result + total, buf, blen);
                total += blen;
                result[total] = 0;
                src = close + 1;
            } else {
                while (total + 2 > cap) { cap *= 2; result = realloc(result, cap); }
                result[total++] = *src;
                result[total] = 0;
                src++;
            }
        } else {
            while (total + 2 > cap) { cap *= 2; result = realloc(result, cap); }
            result[total++] = *src;
            result[total] = 0;
            src++;
        }
    }
    return hexa_str_own(result);
}

// ── String split ─────────────────────────────────────

// Step-3 cycle 45 port — string split dispatches to rt_str_split. The
// hexa path scans byte-by-byte (no strstr) and avoids the strdup/free
// pair the C body uses for the in-place NUL terminator trick.
#ifndef HEXA_HAS_HEXA_RT_STDLIB
HexaVal hexa_str_split(HexaVal s, HexaVal delim) {
    HexaVal arr = hexa_array_new();
    if (!HX_IS_STR(s) || !HX_IS_STR(delim)) return arr;
    char* src = hxlcl_strdup(HX_STR(s));
    char* d = HX_STR(delim);
    int dlen = hxlcl_strlen(d);
    char* pos = src;
    while (1) {
        char* found = hxlcl_strstr(pos, d);
        if (!found) { arr = hexa_array_push(arr, hexa_str(pos)); break; }
        *found = 0;
        arr = hexa_array_push(arr, hexa_str(pos));
        pos = found + dlen;
    }
    free(src);
    return arr;
}
#else
extern HexaVal rt_str_split(HexaVal s, HexaVal delim);
HexaVal hexa_str_split(HexaVal s, HexaVal delim) {
    if (!HX_IS_STR(s) || !HX_IS_STR(delim)) return hexa_array_new();
    return rt_str_split(s, delim);
}
#endif

