// fast path, keeping the result type consistent with `hexa_add_slow`.
#define _HX_COERCE_BOOL(_a, _b) do { \
    if (HX_IS_BOOL(_a)) _a = hexa_int(HX_BOOL(_a) ? 1 : 0); \
    if (HX_IS_BOOL(_b)) _b = hexa_int(HX_BOOL(_b) ? 1 : 0); \
} while (0)
HexaVal hexa_sub(HexaVal a, HexaVal b) {
    _HX_COERCE_BOOL(a, b);
    if (HX_IS_INT(a) && HX_IS_INT(b)) return hexa_int(HX_INT(a) - HX_INT(b));
    if (HX_IS_FLOAT(a) && HX_IS_FLOAT(b)) return hexa_float(HX_FLOAT(a) - HX_FLOAT(b));
    return hexa_float(__hx_to_double(a) - __hx_to_double(b));
}
HexaVal hexa_mul(HexaVal a, HexaVal b) {
    _HX_COERCE_BOOL(a, b);
    if (HX_IS_INT(a) && HX_IS_INT(b)) return hexa_int(HX_INT(a) * HX_INT(b));
    if (HX_IS_FLOAT(a) && HX_IS_FLOAT(b)) return hexa_float(HX_FLOAT(a) * HX_FLOAT(b));
    return hexa_float(__hx_to_double(a) * __hx_to_double(b));
}
// FMA: fused multiply-add — fma(a,b,c) = a*b + c
// For floats uses C99 fma() (single rounding, hardware FMA on modern CPUs).
// For pure ints falls back to a*b+c with int arithmetic.
#ifndef HEXA_HAS_HEXA_RT_STDLIB
HexaVal hexa_fma(HexaVal a, HexaVal b, HexaVal c) {
    if (HX_IS_INT(a) && HX_IS_INT(b) && HX_IS_INT(c))
        return hexa_int(HX_INT(a) * HX_INT(b) + HX_INT(c));
    return hexa_float(fma(__hx_to_double(a), __hx_to_double(b), __hx_to_double(c)));
}
#else
extern HexaVal rt_fma_int(HexaVal a, HexaVal b, HexaVal c);
extern HexaVal rt_fma_float(HexaVal a, HexaVal b, HexaVal c);
HexaVal hexa_fma(HexaVal a, HexaVal b, HexaVal c) {
    if (HX_IS_INT(a) && HX_IS_INT(b) && HX_IS_INT(c))
        return rt_fma_int(a, b, c);
    return rt_fma_float(hexa_float(__hx_to_double(a)),
                        hexa_float(__hx_to_double(b)),
                        hexa_float(__hx_to_double(c)));
}
#endif
HexaVal hexa_div(HexaVal a, HexaVal b) {
    _HX_COERCE_BOOL(a, b);
    if (HX_IS_INT(a) && HX_IS_INT(b)) {
        // 이전엔 silent 0 반환 → 버그 은폐. interp 는 이미 throw + void.
        // hexa_throw 는 try-stack 이 있으면 longjmp, 없으면 stderr + exit.
        if (HX_INT(b) == 0) { hexa_throw(hexa_str("division by zero")); return hexa_int(0); }
        return hexa_int(HX_INT(a) / HX_INT(b));
    }
    if (HX_IS_FLOAT(a) && HX_IS_FLOAT(b)) {
        if (HX_FLOAT(b) == 0.0) { hexa_throw(hexa_str("division by zero")); return hexa_float(0.0); }
        return hexa_float(HX_FLOAT(a) / HX_FLOAT(b));
    }
    double fb = __hx_to_double(b);
    if (fb == 0.0) { hexa_throw(hexa_str("division by zero")); return hexa_float(0.0); }
    return hexa_float(__hx_to_double(a) / fb);
}
HexaVal hexa_mod(HexaVal a, HexaVal b) {
    _HX_COERCE_BOOL(a, b);
    if (HX_IS_INT(a) && HX_IS_INT(b)) {
        if (HX_INT(b) == 0) { hexa_throw(hexa_str("modulo by zero")); return hexa_int(0); }
        return hexa_int(HX_INT(a) % HX_INT(b));
    }
    double fb = __hx_to_double(b);
    if (fb == 0.0) { hexa_throw(hexa_str("modulo by zero")); return hexa_float(0.0); }
    return hexa_float(hxlcl_fmod(__hx_to_double(a), fb));
}

// ROI-44: comparison runtime helpers — replace inline GCC stmt-expr in codegen.
// Semantics: TAG_FLOAT promotes to double compare; TAG_INT uses int64 compare.
// 2026-04-17: TAG_VALSTRUCT (interpreter Val wrapper) routes through
// __hx_to_double so wrapped ints compare on the inner value rather than
// HX_INT(v) reading the .vs pointer as garbage. Symptom before fix:
// `let x = 5; let z = 1 + x` returned 0xA00000005 because val_int's cache
// range check `n < __VAL_INT_CACHE_LEN` mis-evaluated when one side was
// a wrapped Val from the cached singleton table.
// String comparisons via strcmp — 이전 경로는 __hx_to_double("abc") = atof
// 으로 fallthrough 해서 대부분 0.0 으로 수렴 + intern pointer 비교로 떨어져
// 의미 없는 순서 (abc>abb=false 같은 오류).
HexaVal hexa_cmp_lt(HexaVal a, HexaVal b) {
    if (HX_IS_STR(a) && HX_IS_STR(b))
        return hexa_bool(hxlcl_strcmp(HX_STR(a), HX_STR(b)) < 0);
    if (HX_IS_FLOAT(a) || HX_IS_FLOAT(b) || HX_IS_VALSTRUCT(a) || HX_IS_VALSTRUCT(b))
        return hexa_bool(__hx_to_double(a) < __hx_to_double(b));
    return hexa_bool(HX_INT(a) < HX_INT(b));
}
HexaVal hexa_cmp_gt(HexaVal a, HexaVal b) {
    if (HX_IS_STR(a) && HX_IS_STR(b))
        return hexa_bool(hxlcl_strcmp(HX_STR(a), HX_STR(b)) > 0);
    if (HX_IS_FLOAT(a) || HX_IS_FLOAT(b) || HX_IS_VALSTRUCT(a) || HX_IS_VALSTRUCT(b))
        return hexa_bool(__hx_to_double(a) > __hx_to_double(b));
    return hexa_bool(HX_INT(a) > HX_INT(b));
}
HexaVal hexa_cmp_le(HexaVal a, HexaVal b) {
    if (HX_IS_STR(a) && HX_IS_STR(b))
        return hexa_bool(hxlcl_strcmp(HX_STR(a), HX_STR(b)) <= 0);
    if (HX_IS_FLOAT(a) || HX_IS_FLOAT(b) || HX_IS_VALSTRUCT(a) || HX_IS_VALSTRUCT(b))
        return hexa_bool(__hx_to_double(a) <= __hx_to_double(b));
    return hexa_bool(HX_INT(a) <= HX_INT(b));
}
HexaVal hexa_cmp_ge(HexaVal a, HexaVal b) {
    if (HX_IS_STR(a) && HX_IS_STR(b))
        return hexa_bool(hxlcl_strcmp(HX_STR(a), HX_STR(b)) >= 0);
    if (HX_IS_FLOAT(a) || HX_IS_FLOAT(b) || HX_IS_VALSTRUCT(a) || HX_IS_VALSTRUCT(b))
        return hexa_bool(__hx_to_double(a) >= __hx_to_double(b));
    return hexa_bool(HX_INT(a) >= HX_INT(b));
}

// Step-3 cycle 58 port — float fast-path bridge. Mixed-type arrays
// stay on the polymorphic hexa_eq path. Int return preserved (codegen
// wraps in `hexa_bool(...)` like starts_with). _arr_all_float helper
// is inlined here (lives static in runtime.c — copy-pattern from
// hexa_array_reverse above).
#ifndef HEXA_HAS_HEXA_RT_STDLIB
int hexa_array_contains(HexaVal arr, HexaVal item) {
    if (!HX_IS_ARRAY(arr)) return 0;
    for (int i = 0; i < HX_ARR_LEN(arr); i++) {
        if (hexa_truthy(hexa_eq(HX_ARR_ITEMS(arr)[i], item))) return 1;
    }
    return 0;
}
#else
extern HexaVal rt_array_contains_float_b(HexaVal arr, HexaVal item);
int hexa_array_contains(HexaVal arr, HexaVal item) {
    if (!HX_IS_ARRAY(arr)) return 0;
    if (HX_IS_FLOAT(item)) {
        int all_float = 1;
        int64_t n = HX_ARR_LEN(arr);
        for (int64_t i = 0; i < n; i++) {
            if (!HX_IS_FLOAT(HX_ARR_ITEMS(arr)[i])) { all_float = 0; break; }
        }
        if (all_float) {
            return hexa_truthy(rt_array_contains_float_b(arr, item)) ? 1 : 0;
        }
    }
    for (int i = 0; i < HX_ARR_LEN(arr); i++) {
        if (hexa_truthy(hexa_eq(HX_ARR_ITEMS(arr)[i], item))) return 1;
    }
    return 0;
}
#endif

// count_substr(s, substr): number of non-overlapping occurrences.
// Matches interpreter's greedy advance (hexa_full.hexa:14954-14973).
// Step-3 cycle 27 port.
#ifndef HEXA_HAS_HEXA_RT_STDLIB
HexaVal hexa_str_count_substr(HexaVal s, HexaVal sub) {
    if (!HX_IS_STR(s) || !HX_IS_STR(sub)) return hexa_int(0);
    const char* src = HX_STR(s);
    const char* pat = HX_STR(sub);
    int plen = (int)hxlcl_strlen(pat);
    if (plen == 0) return hexa_int(0);
    int64_t cnt = 0;
    const char* p = src;
    while ((p = hxlcl_strstr(p, pat)) != NULL) {
        cnt++;
        p += plen; // non-overlapping
    }
    return hexa_int(cnt);
}
#else
extern HexaVal rt_str_count_substr(HexaVal s, HexaVal sub);
HexaVal hexa_str_count_substr(HexaVal s, HexaVal sub) {
    if (!HX_IS_STR(s) || !HX_IS_STR(sub)) return hexa_int(0);
    return rt_str_count_substr(s, sub);
}
#endif

// Step-3 cycle 60 port — snprintf "%.*f" replaced by hexa-source
// rt_format_float_f. Caveats: works exactly for values within ±2^53
// and prec ≤ 18; beyond that the int64 round-trip is lossy. The C
// body remains as the no-stdlib fallback.
#ifndef HEXA_HAS_HEXA_RT_STDLIB
HexaVal hexa_format_float(HexaVal f, HexaVal prec) {
    double v = __hx_to_double(f);
    int p = HX_INT(prec);
    char buf[64];
    snprintf(buf, 64, "%.*f", p, v);
    return hexa_str(buf);
}
#else
extern HexaVal rt_format_float_f(HexaVal v, HexaVal prec);
HexaVal hexa_format_float(HexaVal f, HexaVal prec) {
    return rt_format_float_f(hexa_float(__hx_to_double(f)), prec);
}
#endif

// Step-3 cycle 61 port — snprintf "%.*e" replaced by hexa-source.
// Uses rt_log10 for the exponent, rt_format_float_f for the mantissa.
// Caveats: same int64 round-trip limit as cycle 60; mantissa rounding
// boundary (9.99→10) is NOT renormalized.
#ifndef HEXA_HAS_HEXA_RT_STDLIB
HexaVal hexa_format_float_sci(HexaVal f, HexaVal prec) {
    double v = __hx_to_double(f);
    int p = HX_INT(prec);
    char buf[64];
    snprintf(buf, 64, "%.*e", p, v);
    return hexa_str(buf);
}
#else
extern HexaVal rt_format_float_sci(HexaVal v, HexaVal prec);
HexaVal hexa_format_float_sci(HexaVal f, HexaVal prec) {
    return rt_format_float_sci(hexa_float(__hx_to_double(f)), prec);
}
#endif

/* amalgam END runtime_core.c */

// RUNTIME.md step-2 cycle 1 POC — thin C shim for `hxlcl_isalnum`/_isalpha
// delegating to hexa-source `rt_isalnum`/_isalpha (in stdlib/runtime/
// ctype.hexa, emitted into ap_post.c by transpile). Two scenarios:
//
//   (a) full aprime_cc build: ap_post.c defines `HEXA_HAS_HEXA_RT_STDLIB`
//       above `#include "runtime.c"` (build_aprime.sh post-process
//       prepends it), the hexa-source rt_isalnum/rt_isalpha definitions
//       win as the strong symbols, and the C fallbacks here are
//       skipped.
//
//   (b) standalone smoke / consumer build: no hexa stdlib transpile
//       output, so runtime.c provides the C fallback bodies. These
//       mirror the hexa source 1-for-1 (ASCII classifiers — locale-
//       free per ANSI C).
#ifndef HEXA_HAS_HEXA_RT_STDLIB
HexaVal rt_isalnum(HexaVal c) {
    int64_t v = HX_INT(c);
    int b = ((v >= 48 && v <= 57) ||
             (v >= 65 && v <= 90) ||
             (v >= 97 && v <= 122)) ? 1 : 0;
    return hexa_bool(b);
}
HexaVal rt_isalpha(HexaVal c) {
    int64_t v = HX_INT(c);
    int b = ((v >= 65 && v <= 90) ||
             (v >= 97 && v <= 122)) ? 1 : 0;
    return hexa_bool(b);
}
#else
extern HexaVal rt_isalnum(HexaVal c);
extern HexaVal rt_isalpha(HexaVal c);
#endif
static int hxlcl_isalnum(int c) {
    return hexa_truthy(rt_isalnum(hexa_int((int64_t)c))) ? 1 : 0;
}
static int hxlcl_isalpha(int c) {
    return hexa_truthy(rt_isalpha(hexa_int((int64_t)c))) ? 1 : 0;
}

// RUNTIME.md step-2 cycle 2 — math helper hexa-source delegation.
// Source of truth: stdlib/runtime/math.hexa. Same #ifndef pattern
// as cycle 1: ap_post.c gets the macro, fallback C body skipped.
#ifndef HEXA_HAS_HEXA_RT_STDLIB
HexaVal rt_fmod(HexaVal x, HexaVal y) {
    double dx = HX_FLOAT(x), dy = HX_FLOAT(y);
    if (dy == 0.0) return hexa_float(0.0);
    double q = dx / dy;
    long long iq = (long long)q;
    return hexa_float(dx - (double)iq * dy);
}
HexaVal rt_exp(HexaVal x) {
    double dx = HX_FLOAT(x);
    const double LN2 = 0.6931471805599453;
    double n_d = dx / LN2;
    long long n = (long long)(n_d + (n_d >= 0.0 ? 0.5 : -0.5));
    double r = dx - (double)n * LN2;
    double r2 = r*r, r3 = r2*r, r4 = r2*r2;
    double sum = 1.0 + r + r2*0.5 + r3*(1.0/6.0) + r4*(1.0/24.0)
                 + r4*r*(1.0/120.0) + r4*r2*(1.0/720.0) + r4*r3*(1.0/5040.0);
    double pow2 = 1.0;
    if (n > 1023) n = 1023;
    if (n < -1022) n = -1022;
    if (n >= 0) for (long long i = 0; i < n; i++) pow2 *= 2.0;
    else for (long long i = 0; i < -n; i++) pow2 *= 0.5;
    return hexa_float(sum * pow2);
}
HexaVal rt_log(HexaVal x) {
    double dx = HX_FLOAT(x);
    if (dx <= 0.0) return hexa_float(-1e308);
    int e = 0;
    while (dx >= 2.0) { dx *= 0.5; e++; }
    while (dx < 1.0) { dx *= 2.0; e--; }
    double u = (dx - 1.0) / (dx + 1.0);
    double u2 = u*u, u3 = u2*u, u5 = u3*u2, u7 = u5*u2;
    double sum = 2.0 * (u + u3/3.0 + u5/5.0 + u7/7.0 + u7*u2/9.0);
    return hexa_float(sum + (double)e * 0.6931471805599453);
}
HexaVal rt_cos(HexaVal x) {
    double dx = HX_FLOAT(x);
    const double TWO_PI = 6.283185307179586;
    const double PI = 3.141592653589793;
    if (dx < 0.0) dx = -dx;
    while (dx >= TWO_PI) dx -= TWO_PI;
    if (dx > PI) dx = TWO_PI - dx;
    double x2 = dx*dx, x4 = x2*x2, x6 = x4*x2, x8 = x4*x4;
    double sum = 1.0 - x2/2.0 + x4/24.0 - x6/720.0 + x8/40320.0
                 - x8*x2/3628800.0 + x8*x4/479001600.0 - x8*x6/87178291200.0;
    return hexa_float(sum);
}
HexaVal rt_sin(HexaVal x) {
    const double PI_HALF = 1.5707963267948966;
    HexaVal shifted = hexa_float(HX_FLOAT(x) - PI_HALF);
    return rt_cos(shifted);
}
#else
extern HexaVal rt_fmod(HexaVal x, HexaVal y);
extern HexaVal rt_exp(HexaVal x);
extern HexaVal rt_log(HexaVal x);
extern HexaVal rt_cos(HexaVal x);
extern HexaVal rt_sin(HexaVal x);
#endif
static double hxlcl_fmod(double x, double y) {
    return HX_FLOAT(rt_fmod(hexa_float(x), hexa_float(y)));
}
static double hxlcl_exp(double x) { return HX_FLOAT(rt_exp(hexa_float(x))); }
static double hxlcl_log(double x) { return HX_FLOAT(rt_log(hexa_float(x))); }
static double hxlcl_cos(double x) { return HX_FLOAT(rt_cos(hexa_float(x))); }
static double hxlcl_sin(double x) { return HX_FLOAT(rt_sin(hexa_float(x))); }

