        double fji_re = sign_y * fij_re;
        double fji_im = sign_y * fij_im;
        double ri = re[i], ii = im[i];
        double rj = re[j], ij = im[j];
        // new_amp_i = c*(ri,ii) + (fji_re,fji_im)*(rj,ij)
