/* F function (BF round) */
static inline uint32_t blf_F(blf_ctx* c, uint32_t x) {
    uint16_t a, b, ccc, d;
    uint32_t y;
    d = (uint16_t)(x & 0xFF); x >>= 8;
    ccc = (uint16_t)(x & 0xFF); x >>= 8;
    b = (uint16_t)(x & 0xFF); x >>= 8;
    a = (uint16_t)(x & 0xFF);
    y = c->S[0][a] + c->S[1][b];
    y = y ^ c->S[2][ccc];
    y = y + c->S[3][d];
    return y;
}

static void blf_encrypt(blf_ctx* c, uint32_t* xl, uint32_t* xr) {
    uint32_t Xl = *xl, Xr = *xr, temp;
    int i;
    for (i = 0; i < BF_N; i++) {
        Xl = Xl ^ c->P[i];
        Xr = blf_F(c, Xl) ^ Xr;
        temp = Xl; Xl = Xr; Xr = temp;
    }
    temp = Xl; Xl = Xr; Xr = temp;
    Xr ^= c->P[BF_N];
    Xl ^= c->P[BF_N + 1];
    *xl = Xl; *xr = Xr;
}

static uint32_t bf_stream2word(const uint8_t* data, uint16_t databytes, uint16_t* current) {
    uint8_t i;
    uint16_t j = *current;
    uint32_t temp = 0;
    for (i = 0; i < 4; i++) {
        if (j >= databytes) j = 0;
        temp = (temp << 8) | data[j];
        j++;
    }
    *current = j;
    return temp;
}

static void blf_initstate(blf_ctx* c) {
    memcpy(c->S, blf_s_init, sizeof(c->S));
    memcpy(c->P, blf_p_init, sizeof(c->P));
}

static void blf_expand_state(blf_ctx* c, const uint8_t* salt, uint16_t saltlen,
                              const uint8_t* key, uint16_t keylen) {
    uint16_t i;
    uint32_t temp, datal = 0, datar = 0;
    uint16_t curr = 0;
    for (i = 0; i < BF_N + 2; i++) {
        temp = bf_stream2word(key, keylen, &curr);
        c->P[i] ^= temp;
    }
    curr = 0;
    for (i = 0; i < BF_N + 2; i += 2) {
        datal ^= bf_stream2word(salt, saltlen, &curr);
        datar ^= bf_stream2word(salt, saltlen, &curr);
        blf_encrypt(c, &datal, &datar);
        c->P[i] = datal;
        c->P[i + 1] = datar;
    }
    for (i = 0; i < 4; i++) {
        for (uint16_t j = 0; j < 256; j += 2) {
            datal ^= bf_stream2word(salt, saltlen, &curr);
            datar ^= bf_stream2word(salt, saltlen, &curr);
            blf_encrypt(c, &datal, &datar);
            c->S[i][j] = datal;
            c->S[i][j + 1] = datar;
        }
    }
}

static void blf_expand0_state(blf_ctx* c, const uint8_t* key, uint16_t keylen) {
    uint16_t i;
    uint32_t temp, datal = 0, datar = 0;
    uint16_t curr = 0;
    for (i = 0; i < BF_N + 2; i++) {
        temp = bf_stream2word(key, keylen, &curr);
        c->P[i] ^= temp;
    }
    for (i = 0; i < BF_N + 2; i += 2) {
        blf_encrypt(c, &datal, &datar);
        c->P[i] = datal;
        c->P[i + 1] = datar;
    }
    for (i = 0; i < 4; i++) {
        for (uint16_t j = 0; j < 256; j += 2) {
            blf_encrypt(c, &datal, &datar);
            c->S[i][j] = datal;
            c->S[i][j + 1] = datar;
        }
    }
}

/* bcrypt_hash inner — produces 32 bytes from SHA-512 hashed pw + salt. */
static void bcrypt_hash(const uint8_t* sha2pass, const uint8_t* sha2salt, uint8_t* out) {
    blf_ctx state;
    /* "OxychromaticBlowfishSwatDynamite" 32 bytes */
    uint8_t ciphertext[BCRYPT_HASHSIZE] = {
        'O','x','y','c','h','r','o','m','a','t','i','c','B','l','o','w',
        'f','i','s','h','S','w','a','t','D','y','n','a','m','i','t','e'
    };
    uint32_t cdata[BCRYPT_BLOCKS];
    int i;
    uint16_t curr = 0;

    blf_initstate(&state);
    blf_expand_state(&state, sha2salt, 64, sha2pass, 64);
    for (i = 0; i < 64; i++) {
        blf_expand0_state(&state, sha2salt, 64);
        blf_expand0_state(&state, sha2pass, 64);
    }

    for (i = 0; i < BCRYPT_BLOCKS; i++) {
        cdata[i] = bf_stream2word(ciphertext, BCRYPT_HASHSIZE, &curr);
    }
    for (i = 0; i < 64; i++) {
        int j;
        for (j = 0; j < BCRYPT_BLOCKS / 2; j++) {
            blf_encrypt(&state, &cdata[2 * j], &cdata[2 * j + 1]);
        }
    }
    for (i = 0; i < BCRYPT_BLOCKS; i++) {
        out[4 * i + 3] = (uint8_t)(cdata[i] >> 24);
        out[4 * i + 2] = (uint8_t)(cdata[i] >> 16);
        out[4 * i + 1] = (uint8_t)(cdata[i] >> 8);
        out[4 * i + 0] = (uint8_t)(cdata[i] & 0xff);
    }
}

/* libsodium's SHA-512 wrapper (declared earlier in runtime.c via the
 * crypto_sodium.c include) — we re-declare a low-level path here. We
 * just use libsodium's crypto_hash_sha512 directly. */
#ifdef HEXA_HAS_LIBSODIUM
#include <sodium.h>
#endif

/* Public function: bcrypt_pbkdf(pass, salt, rounds) -> key bytes
 * Matches OpenBSD bcrypt_pbkdf(pass, passlen, salt, saltlen, key,
 * keylen, rounds). Returns the derived key as [int]. */
HexaVal hexa_bcrypt_pbkdf(HexaVal pass_v, HexaVal salt_v, HexaVal rounds_v, HexaVal keylen_v) {
#ifdef HEXA_HAS_LIBSODIUM
    if (!_ensure_sodium()) return _crypto_error("libsodium init failed");
    size_t pass_n = 0, salt_n = 0;
    unsigned char* pass = _arr_to_bytes(pass_v, &pass_n);
    unsigned char* salt = _arr_to_bytes(salt_v, &salt_n);
    int rounds = HX_IS_INT(rounds_v) ? (int)HX_INT(rounds_v) : 0;
    int keylen = HX_IS_INT(keylen_v) ? (int)HX_INT(keylen_v) : 0;
    if (!pass || !salt || rounds < 1 || keylen < 1 || keylen > 1024) {
        if (pass) free(pass); if (salt) free(salt);
        return _crypto_error("bcrypt_pbkdf: bad inputs");
    }

    uint8_t sha2pass[64];
    uint8_t sha2salt[64];
    uint8_t out[BCRYPT_HASHSIZE];
    uint8_t tmpout[BCRYPT_HASHSIZE];
    uint8_t* key = (uint8_t*)calloc(keylen, 1);
    if (!key) { free(pass); free(salt); return _crypto_error("bcrypt_pbkdf: oom"); }

    int origkeylen = keylen;
    int stride = (keylen + BCRYPT_HASHSIZE - 1) / BCRYPT_HASHSIZE;
    int amt = (keylen + stride - 1) / stride;

    crypto_hash_sha512(sha2pass, pass, pass_n);

    uint32_t count = 1;
    while (keylen > 0) {
        /* countsalt = salt || u32_be(count) */
        uint8_t* countsalt = (uint8_t*)malloc(salt_n + 4);
        memcpy(countsalt, salt, salt_n);
        countsalt[salt_n + 0] = (uint8_t)((count >> 24) & 0xff);
        countsalt[salt_n + 1] = (uint8_t)((count >> 16) & 0xff);
        countsalt[salt_n + 2] = (uint8_t)((count >> 8)  & 0xff);
        countsalt[salt_n + 3] = (uint8_t)( count        & 0xff);

        crypto_hash_sha512(sha2salt, countsalt, salt_n + 4);
        bcrypt_hash(sha2pass, sha2salt, tmpout);
        memcpy(out, tmpout, BCRYPT_HASHSIZE);

        for (int i = 1; i < rounds; i++) {
            crypto_hash_sha512(sha2salt, tmpout, BCRYPT_HASHSIZE);
            bcrypt_hash(sha2pass, sha2salt, tmpout);
            for (int j = 0; j < BCRYPT_HASHSIZE; j++) out[j] ^= tmpout[j];
        }

        int amt_this = amt;
        if (amt_this > keylen) amt_this = keylen;
        int i;
        for (i = 0; i < amt_this; i++) {
            int dest = i * stride + (count - 1);
            if (dest >= origkeylen) break;
            key[dest] = out[i];
        }
        keylen -= i;
        count++;
        free(countsalt);
    }

    HexaVal res = _bytes_to_arr(key, origkeylen);
    free(key); free(pass); free(salt);
    return res;
#else
    (void)pass_v; (void)salt_v; (void)rounds_v; (void)keylen_v;
    return _crypto_error("libsodium required (for sha512)");
#endif
}
/* amalgam END native/crypto_blowfish.c */
/* amalgam BEGIN native/crypto_openssl.c */
/* self/native/crypto_openssl.c -- OpenSSL EVP binding (AES-256-CTR).
 *
 * Included from self/runtime.c (NOT a standalone TU).
 *
 * Only AES-256-CTR for now — needed by OpenSSH passphrase-encrypted
 * private-key decryption (cipher = "aes256-ctr"). libsodium ships
 * AES-128 only; AES-256 needs OpenSSL or a hand-rolled S-box impl.
 *
 * Exports:
 *   hexa_aes256_ctr_xor(key, iv, data) -> [int]
 *
 * Linking: -lcrypto (OpenSSL). Detected by self/main.hexa::os_clang_*
 * flags via pkg-config openssl when HEXA_HAS_OPENSSL is defined.
 */

#ifdef HEXA_HAS_OPENSSL
#include <openssl/evp.h>
#endif

HexaVal hexa_aes256_ctr_xor(HexaVal key_v, HexaVal iv_v, HexaVal data_v) {
#ifdef HEXA_HAS_OPENSSL
    size_t kn = 0, in = 0, dn = 0;
    unsigned char* k = _arr_to_bytes(key_v,  &kn);
    unsigned char* iv = _arr_to_bytes(iv_v,  &in);
    unsigned char* d = _arr_to_bytes(data_v, &dn);
    if (!k || kn != 32 || !iv || in != 16 || !d) {
        if (k) free(k); if (iv) free(iv); if (d) free(d);
        return _crypto_error("aes256_ctr: key=32 iv=16 required");
    }
    EVP_CIPHER_CTX* ctx = EVP_CIPHER_CTX_new();
    if (!ctx) { free(k); free(iv); free(d); return _crypto_error("aes256_ctr: ctx_new"); }
    unsigned char* out = (unsigned char*)malloc(dn);
    int outlen = 0, finlen = 0;
    int ok = EVP_EncryptInit_ex(ctx, EVP_aes_256_ctr(), NULL, k, iv) == 1
          && EVP_EncryptUpdate(ctx, out, &outlen, d, (int)dn) == 1
          && EVP_EncryptFinal_ex(ctx, out + outlen, &finlen) == 1;
    EVP_CIPHER_CTX_free(ctx);
    HexaVal res;
    if (ok) { res = _bytes_to_arr(out, dn); }
    else { res = _crypto_error("aes256_ctr: EVP failed"); }
    free(k); free(iv); free(d); free(out);
    return res;
#else
    (void)key_v; (void)iv_v; (void)data_v;
    return _crypto_error("OpenSSL not linked — passphrase-encrypted keys unsupported");
#endif
}
/* amalgam END native/crypto_openssl.c */
/* amalgam BEGIN native/exec_pipe.c */
/* self/native/exec_pipe.c -- fork + exec with separated stdout/stderr pipes.
 *
 * Included from self/runtime.c (NOT a standalone TU).
 *
 * Unlike hexa_pty_forkexec (which uses a pty so stdout and stderr both
 * fall down the master_fd), this binding gives the caller two distinct
 * fds — needed by sshd to route stdout to CHANNEL_DATA and stderr to
 * CHANNEL_EXTENDED_DATA(1) per RFC 4254 §5.2.
 *
 * Exports (codegen direct-emit):
 *   hexa_exec_pipe_open(argv, env)
 *     -> map { pid:int, stdout_fd:int, stderr_fd:int, stdin_fd:int }
 *     or { error: string }
 *
 * Lifecycle: caller is responsible for net_close(stdout_fd) /
 * net_close(stderr_fd) / net_close(stdin_fd) and proc_wait(pid).
 */

#include <sys/types.h>
#include <sys/wait.h>
#include <unistd.h>
#include <fcntl.h>
#include <errno.h>
#include <string.h>
#include <stdlib.h>

HexaVal hexa_exec_pipe_open(HexaVal argv_v, HexaVal env_v) {
    if (!HX_IS_ARRAY(argv_v)) return _crypto_error("exec_pipe_open: argv must be array");
    int argc = HX_ARR_LEN(argv_v);
    if (argc < 1) return _crypto_error("exec_pipe_open: empty argv");
    /* Materialize argv */
    char** argv = (char**)malloc(sizeof(char*) * (size_t)(argc + 1));
    if (!argv) return _crypto_error("exec_pipe_open: oom argv");
    for (int i = 0; i < argc; i++) {
        HexaVal v = HX_ARR_ITEMS(argv_v)[i];
        const char* s = HX_IS_STR(v) ? HX_STR(v) : "";
        argv[i] = strdup(s ? s : "");
    }
    argv[argc] = NULL;

    /* Materialize env: [string] of "KEY=VALUE" entries (NULL-terminated). */
    char** envp = NULL;
    int envc = 0;
    if (HX_IS_ARRAY(env_v)) {
        envc = HX_ARR_LEN(env_v);
        envp = (char**)malloc(sizeof(char*) * (size_t)(envc + 1));
        for (int i = 0; i < envc; i++) {
            HexaVal v = HX_ARR_ITEMS(env_v)[i];
            const char* s = HX_IS_STR(v) ? HX_STR(v) : "";
            envp[i] = strdup(s ? s : "");
        }
        envp[envc] = NULL;
    }

    int p_stdin[2], p_stdout[2], p_stderr[2];
    if (hxlcl_pipe(p_stdin)  != 0) { /* fall through to cleanup */ goto fail_pipe; }
    if (hxlcl_pipe(p_stdout) != 0) { hxlcl_close(p_stdin[0]); hxlcl_close(p_stdin[1]); goto fail_pipe; }
    if (hxlcl_pipe(p_stderr) != 0) {
        hxlcl_close(p_stdin[0]); hxlcl_close(p_stdin[1]);
        hxlcl_close(p_stdout[0]); hxlcl_close(p_stdout[1]);
        goto fail_pipe;
    }

    pid_t pid = hxlcl_fork();
    if (pid < 0) {
        hxlcl_close(p_stdin[0]); hxlcl_close(p_stdin[1]);
        hxlcl_close(p_stdout[0]); hxlcl_close(p_stdout[1]);
        hxlcl_close(p_stderr[0]); hxlcl_close(p_stderr[1]);
        for (int i = 0; i < argc; i++) free(argv[i]);
        free(argv);
        if (envp) { for (int i = 0; i < envc; i++) free(envp[i]); free(envp); }
        return _crypto_error("exec_pipe_open: fork failed");
    }
    if (pid == 0) {
        /* child */
        hxlcl_dup2(p_stdin[0],  STDIN_FILENO);
        hxlcl_dup2(p_stdout[1], STDOUT_FILENO);
        hxlcl_dup2(p_stderr[1], STDERR_FILENO);
        hxlcl_close(p_stdin[0]);  hxlcl_close(p_stdin[1]);
        hxlcl_close(p_stdout[0]); hxlcl_close(p_stdout[1]);
        hxlcl_close(p_stderr[0]); hxlcl_close(p_stderr[1]);
        /* execvp does PATH lookup, which we need for short names like
         * "sh". When an envp[] is supplied, switch `environ` over so
         * the child inherits exactly those vars but execvp still
         * finds the binary on PATH. */
        if (envp && envc > 0) {
            extern char** environ;
            environ = envp;
        }
        hxlcl_execvp(argv[0], argv);
        /* exec failed */
        _exit(127);
    }
    /* parent */
    hxlcl_close(p_stdin[0]);
    hxlcl_close(p_stdout[1]);
    hxlcl_close(p_stderr[1]);
    for (int i = 0; i < argc; i++) free(argv[i]);
    free(argv);
    if (envp) { for (int i = 0; i < envc; i++) free(envp[i]); free(envp); }

    HexaVal m = hexa_map_new();
    hexa_map_set(m, "pid",        hexa_int((int64_t)pid));
    hexa_map_set(m, "stdin_fd",   hexa_int((int64_t)p_stdin[1]));
    hexa_map_set(m, "stdout_fd",  hexa_int((int64_t)p_stdout[0]));
    hexa_map_set(m, "stderr_fd",  hexa_int((int64_t)p_stderr[0]));
    return m;

fail_pipe:
    for (int i = 0; i < argc; i++) free(argv[i]);
    free(argv);
    if (envp) { for (int i = 0; i < envc; i++) free(envp[i]); free(envp); }
    return _crypto_error("exec_pipe_open: hxlcl_pipe() failed");
}
/* amalgam END native/exec_pipe.c */
/* amalgam BEGIN native/proc_fork.c */
/* self/native/proc_fork.c -- hxlcl_fork() + setsid() + sigchld reap helpers.
 *
 * Included from self/runtime.c (NOT a standalone TU).
 *
 * Exports (codegen direct-emit):
 *   hexa_proc_fork() -> int (0 in child, child_pid in parent, -1 on error)
 *   hexa_proc_setsid() -> int (new sid or -errno)
 *   hexa_proc_reap_zombies() -> int (count of reaped zombies)
 */

#include <sys/types.h>
#include <sys/wait.h>
#include <unistd.h>
#include <errno.h>

HexaVal hexa_proc_fork(void) {
    pid_t pid = hxlcl_fork();
    if (pid < 0) return hexa_int((int64_t)-errno);
    return hexa_int((int64_t)pid);
}

HexaVal hexa_proc_setsid(void) {
    pid_t sid = setsid();
    if (sid < 0) return hexa_int((int64_t)-errno);
    return hexa_int((int64_t)sid);
}

HexaVal hexa_proc_reap_zombies(void) {
    int count = 0;
    while (1) {
        int status = 0;
        pid_t r = hxlcl_waitpid(-1, &status, WNOHANG);
        if (r <= 0) break;
        count++;
    }
    return hexa_int((int64_t)count);
}
/* amalgam END native/proc_fork.c */

/* ═══════════════════════════════════════════════════════════════════
 * B20 / roadmap 55 Phase 1 — deterministic FP control-word init.
 *
 * Exposes void hexa_fp_init(void). codegen.hexa emits a call to it
 * as the first statement of generated main(). Implementation in
 * self/native/fp_init.c normalizes MXCSR (x86_64) or FPCR (aarch64)
 * to IEEE-default behavior (no FTZ/DAZ/FZ, round-to-nearest-even) so
 * @strict_fp functions can rely on bit-exact FP semantics.
 *
 * Phase 2 scope: crlibm vendoring for cross-substrate transcendental
 * identity; pthread_create trampoline. Not shipped in Phase 1.
 * ═══════════════════════════════════════════════════════════════════ */
/* amalgam BEGIN native/fp_init.c */
/* ═══════════════════════════════════════════════════════════════════
 * self/native/fp_init.c — B20 / roadmap 55 Phase 1
 *
 * Per-thread FP control-word normalization for IEEE 754 strict mode.
 *
 * Called unconditionally at main() entry (codegen_c2.hexa emits
 * `hexa_fp_init()` right after hexa_set_args). Idempotent — safe to
 * invoke multiple times or from any thread entry trampoline.
 *
 * Why per-thread: MXCSR (x86_64) and FPCR (aarch64) are thread-local
 * registers. OS/runtime may seed them with FTZ/DAZ/non-IEEE rounding
 * bits enabled (e.g. Intel MKL sets DAZ, Accelerate sets FZ on some
 * paths). Bit-exact cross-substrate FP requires explicit reset in
 * every thread that runs @strict_fp code.
 *
 * Phase 2 will wire hexa_fp_init() into a pthread_create() wrapper
 * (self/native/signal_flock.c pattern) so worker-pool threads inherit
 * the normalized state.
 *
 * Semantics:
 *   x86_64: clear FTZ (bit 15) + DAZ (bit 6) in MXCSR.
 *           Round-to-nearest-even is the default (RC=00), untouched.
 *   aarch64: zero FPCR — clears FZ (bit 24), FZ16 (bit 19), AH (bit 1),
 *            sets round-to-nearest-even (RMode=00), no trapping.
 *   other: no-op (the two-rounding FMA gate in codegen still holds).
 * ═══════════════════════════════════════════════════════════════════ */

#include <stdint.h>

#if defined(__x86_64__) || defined(_M_X64)
#include <xmmintrin.h>
#include <pmmintrin.h>
#endif

static int _hexa_fp_init_done = 0;

void hexa_fp_init(void) {
#if defined(__x86_64__) || defined(_M_X64)
    /* Clear FTZ (0x8000) and DAZ (0x0040) while preserving RC/other. */
    unsigned int csr = _mm_getcsr();
    csr &= ~0x8040u;
    _mm_setcsr(csr);
#elif defined(__aarch64__)
    /* FPCR ← 0: FZ=0, AH=0, RMode=00 (round-to-nearest-even). */
    uint64_t zero = 0;
    __asm__ volatile ("msr fpcr, %0" :: "r"(zero));
#else
    /* Other substrates (ppc64le, riscv64, …): no per-thread FP CSR to
     * normalize here. The codegen-side FMA gate still applies; strict
     * transcendental libm (Phase 2 crlibm vendoring) will carry the
     * remaining portability burden. */
#endif
    _hexa_fp_init_done = 1;
}

/* Observable for self-test / introspection. */
int hexa_fp_init_was_called(void) {
    return _hexa_fp_init_done;
}
/* amalgam END native/fp_init.c */

/* ═══════════════════════════════════════════════════════════════════
 * stdlib/os — signal + flock builtins (roadmap 62, 2026-04-22)
 *
 * Exposes hexa_os_sig_* (install / raise / drain / block / …) and
 * hexa_os_flock_* (open / close) for the stdlib/os/{signal,flock}.hexa
 * modules. Async-signal-safe self-pipe trampoline; O_CLOEXEC on flock
 * fds so hxlcl_execve(3) does not leak locks into children.
 *
 * Implementation: native/signal_flock.c (see header comment for full
 * contract + semantics).
 * ═══════════════════════════════════════════════════════════════════ */
/* iter-2c (2026-05-22): on Linux glibc, <sys/file.h> declares
 * `extern int flock(int __fd, int __operation)`. The `#define flock(fd,op)
 * hxlcl_flock(...)` macro at runtime.c:1187 textually replaces the
 * prototype's parameter names with a call expression, so the parser sees
 * `int hxlcl_flock((int)(__fd), (int)(__operation));` and dies at the `(`.
 * macOS clang's <sys/file.h> does not expose a function-like flock so the
 * macro is a no-op there. Undef just for this include; signal_flock.c uses
 * the libc `flock(fd, op)` form internally (LOCK_EX/LOCK_UN), which is the
 * intended behavior on both platforms. Minimal scope: only this include. */
#undef flock
/* amalgam BEGIN native/signal_flock.c */
/* self/native/signal_flock.c — stdlib/os signal + flock builtins
 *
 * Roadmap item 62 (2026-04-22). Included from self/runtime.c via
 *   #include "native/signal_flock.c"
 * analogous to native/net.c. Pure libc; portable macOS/Linux.
 *
 * Symbols exported (signal — 9 + flock — 2):
 *   hexa_os_sig_install(sig, name_str)  : install async-signal-safe
 *                                         trampoline; stash handler name
 *   hexa_os_sig_uninstall(sig)          : restore SIG_DFL
 *   hexa_os_sig_current(sig)            : installed name ("" if none)
 *   hexa_os_sig_raise(sig)              : hxlcl_kill(getpid, sig)
 *   hexa_os_sig_kill(pid, sig)          : hxlcl_kill(pid, sig)
 *   hexa_os_sig_pipe_fd()               : read-end of self-pipe
 *   hexa_os_sig_drain()                 : array<int> pending signals,
 *                                         drained from pipe
 *   hexa_os_sig_block(arr)              : sigprocmask SIG_BLOCK
 *   hexa_os_sig_unblock(arr)            : sigprocmask SIG_UNBLOCK
 *
 *   hexa_os_flock_open(path, mode_int)  : open O_RDWR|O_CREAT|O_CLOEXEC
 *                                         then flock. mode bits:
 *                                           0 = LOCK_EX  (blocking)
 *                                           1 = LOCK_SH  (blocking)
 *                                           2 = LOCK_EX|LOCK_NB
 *                                           3 = LOCK_SH|LOCK_NB
 *                                         Returns fd >= 0 on success,
 *                                         -errno on failure.
 *   hexa_os_flock_close(fd)             : LOCK_UN + close; returns 0 or
 *                                         -errno.
 *
 * Error model: negative TAG_INT (raw -errno) — matches net.c.
 *
 * Async-signal-safety: __hexa_sig_trampoline uses only hxlcl_write(2), which
 * POSIX lists as async-signal-safe (signal-safety(7)). No malloc, no
 * printf, no lock. The trampoline writes 1 byte == signal number to the
 * self-pipe; the scheduler (pure hexa code) drains via hexa_os_sig_drain.
 *
 * O_CLOEXEC: flock fd is opened CLOEXEC so hxlcl_execve(3) does not leak the
 * lock into child processes (locks are per-(pid,open-file-description)
 * on POSIX, and CLOEXEC avoids accidental lock promotion through exec).
 */

#include <signal.h>
#include <fcntl.h>
#include <errno.h>
#include <unistd.h>
#include <string.h>
#include <sys/file.h>   /* flock(2) */
#include <sys/types.h>

#ifndef NSIG
#define NSIG 64
#endif

/* Per-signal stored handler name. Written under normal program control
 * (hexa_os_sig_install) — not from inside the trampoline. */
static char     g_handler_names[NSIG][64];
static int      g_handler_set[NSIG];
static int      g_sig_pipe[2] = {-1, -1};

/* Async-signal-safe: only calls hxlcl_write(2). */
static void __hexa_sig_trampoline(int sig) {
    if (g_sig_pipe[1] >= 0 && sig > 0 && sig < NSIG) {
        unsigned char b = (unsigned char)sig;
        int saved = errno;
        (void)hxlcl_write(g_sig_pipe[1], &b, 1);
        errno = saved;
    }
}

/* Set O_NONBLOCK + FD_CLOEXEC on fd. Returns 0 / -errno. */
static int _hexa_fd_nonblock_cloexec(int fd) {
    int fl = hxlcl_fcntl(fd, F_GETFL, 0);
    if (fl < 0) return -errno;
    if (hxlcl_fcntl(fd, F_SETFL, fl | O_NONBLOCK) < 0) return -errno;
    int cf = hxlcl_fcntl(fd, F_GETFD, 0);
    if (cf < 0) return -errno;
    if (hxlcl_fcntl(fd, F_SETFD, cf | FD_CLOEXEC) < 0) return -errno;
    return 0;
}

/* Lazy self-pipe init. Thread-compat not guaranteed — single scheduler
 * thread expected (matches async_runtime.hexa). */
static int _hexa_sig_pipe_init(void) {
    if (g_sig_pipe[0] >= 0) return 0;
    int p[2];
    if (hxlcl_pipe(p) < 0) return -errno;
    int rc = _hexa_fd_nonblock_cloexec(p[0]);
    if (rc < 0) { hxlcl_close(p[0]); hxlcl_close(p[1]); return rc; }
    rc = _hexa_fd_nonblock_cloexec(p[1]);
    if (rc < 0) { hxlcl_close(p[0]); hxlcl_close(p[1]); return rc; }
    g_sig_pipe[0] = p[0];
    g_sig_pipe[1] = p[1];
    return 0;
}

HexaVal hexa_os_sig_pipe_fd(void) {
    int rc = _hexa_sig_pipe_init();
    if (rc < 0) return hexa_int(rc);
    return hexa_int(g_sig_pipe[0]);
}

HexaVal hexa_os_sig_install(HexaVal sig_val, HexaVal name_val) {
    if (!HX_IS_INT(sig_val)) return hexa_int(-EINVAL);
    int sig = (int)HX_INT(sig_val);
    if (sig <= 0 || sig >= NSIG) return hexa_int(-EINVAL);
    int rc = _hexa_sig_pipe_init();
    if (rc < 0) return hexa_int(rc);
    struct sigaction act;
    memset(&act, 0, sizeof(act));
    act.sa_handler = __hexa_sig_trampoline;
    act.sa_flags = SA_RESTART;
    sigemptyset(&act.sa_mask);
    if (hxlcl_sigaction(sig, &act, NULL) < 0) return hexa_int(-errno);
    const char* name = HX_IS_STR(name_val) ? HX_STR(name_val) : "";
    size_t nlen = strlen(name);
    if (nlen >= sizeof(g_handler_names[sig])) nlen = sizeof(g_handler_names[sig]) - 1;
    memcpy(g_handler_names[sig], name, nlen);
    g_handler_names[sig][nlen] = '\0';
    g_handler_set[sig] = 1;
    return hexa_int(0);
}

HexaVal hexa_os_sig_uninstall(HexaVal sig_val) {
    if (!HX_IS_INT(sig_val)) return hexa_int(-EINVAL);
    int sig = (int)HX_INT(sig_val);
    if (sig <= 0 || sig >= NSIG) return hexa_int(-EINVAL);
    struct sigaction act;
    memset(&act, 0, sizeof(act));
    act.sa_handler = SIG_DFL;
    sigemptyset(&act.sa_mask);
    if (hxlcl_sigaction(sig, &act, NULL) < 0) return hexa_int(-errno);
    g_handler_names[sig][0] = '\0';
    g_handler_set[sig] = 0;
    return hexa_int(0);
}

HexaVal hexa_os_sig_current(HexaVal sig_val) {
    if (!HX_IS_INT(sig_val)) return hexa_str("");
    int sig = (int)HX_INT(sig_val);
    if (sig <= 0 || sig >= NSIG) return hexa_str("");
    if (!g_handler_set[sig]) return hexa_str("");
    return hexa_str(g_handler_names[sig]);
}

HexaVal hexa_os_sig_raise(HexaVal sig_val) {
    if (!HX_IS_INT(sig_val)) return hexa_int(-EINVAL);
    int sig = (int)HX_INT(sig_val);
    if (hxlcl_kill(hxlcl_getpid(), sig) < 0) return hexa_int(-errno);
    return hexa_int(0);
}

HexaVal hexa_os_sig_kill(HexaVal pid_val, HexaVal sig_val) {
    if (!HX_IS_INT(pid_val) || !HX_IS_INT(sig_val)) return hexa_int(-EINVAL);
    int pid = (int)HX_INT(pid_val);
    int sig = (int)HX_INT(sig_val);
    if (hxlcl_kill(pid, sig) < 0) return hexa_int(-errno);
    return hexa_int(0);
}

/* Drain the self-pipe, returning an array of signal numbers that had
 * been delivered since last drain. Non-blocking. */
HexaVal hexa_os_sig_drain(void) {
    HexaVal arr = hexa_array_new();
    int rc = _hexa_sig_pipe_init();
    if (rc < 0) return arr;
    unsigned char buf[64];
    for (;;) {
        ssize_t n = hxlcl_read(g_sig_pipe[0], buf, sizeof(buf));
        if (n <= 0) break;
        for (ssize_t i = 0; i < n; i++) {
            arr = hexa_array_push(arr, hexa_int((int)buf[i]));
        }
        if ((size_t)n < sizeof(buf)) break;
    }
    return arr;
}

/* sigprocmask helper. which: SIG_BLOCK / SIG_UNBLOCK. arr_val must be
 * HexaVal array of ints. */
static HexaVal _hexa_sig_mask_op(int which, HexaVal arr_val) {
    if (!HX_IS_ARRAY(arr_val)) return hexa_int(-EINVAL);
    sigset_t set;
    sigemptyset(&set);
    int64_t n = (int64_t)HX_ARR_LEN(arr_val);
    for (int64_t i = 0; i < n; i++) {
        HexaVal el = hexa_array_get(arr_val, i);
        if (!HX_IS_INT(el)) continue;
        int sig = (int)HX_INT(el);
        if (sig > 0 && sig < NSIG) sigaddset(&set, sig);
    }
    if (hxlcl_sigprocmask(which, &set, NULL) < 0) return hexa_int(-errno);
    return hexa_int(0);
}

HexaVal hexa_os_sig_block(HexaVal arr_val) {
    return _hexa_sig_mask_op(SIG_BLOCK, arr_val);
}

HexaVal hexa_os_sig_unblock(HexaVal arr_val) {
    return _hexa_sig_mask_op(SIG_UNBLOCK, arr_val);
}

/* ── flock ────────────────────────────────────────────────────── */

/* mode_int:
 *   0 = LOCK_EX (blocking)
 *   1 = LOCK_SH (blocking)
 *   2 = LOCK_EX | LOCK_NB
 *   3 = LOCK_SH | LOCK_NB
 */
HexaVal hexa_os_flock_open(HexaVal path_val, HexaVal mode_val) {
    if (!HX_IS_STR(path_val) || !HX_IS_INT(mode_val)) return hexa_int(-EINVAL);
    const char* path = HX_STR(path_val);
    int mode_bits = (int)HX_INT(mode_val);

    int op;
    switch (mode_bits) {
        case 0: op = LOCK_EX; break;
        case 1: op = LOCK_SH; break;
        case 2: op = LOCK_EX | LOCK_NB; break;
        case 3: op = LOCK_SH | LOCK_NB; break;
        default: return hexa_int(-EINVAL);
    }

    /* O_CLOEXEC mandatory — exec'd children must not inherit the lock fd.
     * POSIX flock(2) semantics: lock is held per open-file-description; if
     * fd leaks via exec, the child would own the lock, surprising the
     * parent's unlock expectations. */
    int fd = hxlcl_open_sys(path, O_RDWR | O_CREAT | O_CLOEXEC, 0644);
    if (fd < 0) return hexa_int(-errno);

    if (flock(fd, op) < 0) {
        int e = errno;
        hxlcl_close(fd);
        return hexa_int(-e);
    }
    return hexa_int(fd);
}

HexaVal hexa_os_flock_close(HexaVal fd_val) {
    if (!HX_IS_INT(fd_val)) return hexa_int(-EINVAL);
    int fd = (int)HX_INT(fd_val);
    if (fd < 0) return hexa_int(-EINVAL);
    /* Best-effort unlock; close always runs. */
    (void)flock(fd, LOCK_UN);
    if (hxlcl_close(fd) < 0) return hexa_int(-errno);
    return hexa_int(0);
}

/* getpid helper (used by .hexa wrappers for raise_signal fallback). */
HexaVal hexa_os_getpid(void) {
    return hexa_int((int64_t)hxlcl_getpid());
}

/* ── TAG_FN shim globals (bootstrap bridge) ──────────────────────
 * Analogous to net.c's _hexa_init_net_fn_shims. Called from runtime.c
 * _hexa_init_fn_shims. After the next hexa_cc bootstrap cycle teaches
 * the transpiler direct-lowering, these globals become harmless. */
HexaVal os_sig_install;
HexaVal os_sig_uninstall;
HexaVal os_sig_current;
HexaVal os_sig_raise;
HexaVal os_sig_kill;
HexaVal os_sig_pipe_fd;
HexaVal os_sig_drain;
HexaVal os_sig_block;
HexaVal os_sig_unblock;
HexaVal os_flock_open;
HexaVal os_flock_close;
HexaVal os_getpid;

static void _hexa_init_os_fn_shims(void) {
    os_sig_install   = hexa_fn_new((void*)hexa_os_sig_install,   2);
    os_sig_uninstall = hexa_fn_new((void*)hexa_os_sig_uninstall, 1);
    os_sig_current   = hexa_fn_new((void*)hexa_os_sig_current,   1);
    os_sig_raise     = hexa_fn_new((void*)hexa_os_sig_raise,     1);
    os_sig_kill      = hexa_fn_new((void*)hexa_os_sig_kill,      2);
    os_sig_pipe_fd   = hexa_fn_new((void*)hexa_os_sig_pipe_fd,   0);
    os_sig_drain     = hexa_fn_new((void*)hexa_os_sig_drain,     0);
    os_sig_block     = hexa_fn_new((void*)hexa_os_sig_block,     1);
    os_sig_unblock   = hexa_fn_new((void*)hexa_os_sig_unblock,   1);
    os_flock_open    = hexa_fn_new((void*)hexa_os_flock_open,    2);
    os_flock_close   = hexa_fn_new((void*)hexa_os_flock_close,   1);
    os_getpid        = hexa_fn_new((void*)hexa_os_getpid,        0);
}
/* amalgam END native/signal_flock.c */

/* ═══════════════════════════════════════════════════════════════════
 * hxa-20260424-005 items #1 + #7 — exec_argv + sha256 (2026-04-24)
 *
 * Exposes:
 *   hexa_exec_argv(argv_arr)             : fork/execvp, no /bin/sh -c
 *   hexa_exec_argv_with_status(argv_arr) : same + exit code
 *   hexa_sha256(s)                       : lowercase hex digest
 *   hexa_sha256_file(path)               : lowercase hex digest of file
 *
 * Implementation: native/exec_argv_sha256.c (pure libc + FIPS 180-4
 * reference sha256). TAG_FN shims registered from _hexa_init_fn_shims
 * so the interpreter path resolves `exec_argv`/`sha256` names before
 * the transpiler learns direct-lowering.
 * ═══════════════════════════════════════════════════════════════════ */
/* amalgam BEGIN native/exec_argv_sha256.c */
/* self/native/exec_argv_sha256.c
 *
 * hxa-20260424-005 items #1 + #7 (2026-04-24).
 *
 * Two pure-libc/Zig-stdlib-equivalent builtins:
 *
 *   hexa_exec_argv(argv_arr)             : HexaVal array<str> → HexaVal str
 *   hexa_exec_argv_with_status(argv_arr) : HexaVal array<str> → HexaVal [str,int]
 *       Direct fork/execvp without `/bin/sh -c`. No shell metachar expansion.
 *       argv_arr[0] is the program (searched via PATH if not absolute).
 *       argv_arr[1..] are arguments passed verbatim to the child.
 *
 *   hexa_sha256(s)                       : HexaVal str → HexaVal str (lowercase hex)
 *   hexa_sha256_file(path)               : HexaVal str → HexaVal str (lowercase hex of file bytes)
 *       FIPS 180-4 reference implementation. Returns 64-char lowercase hex.
 *       sha256_file returns "" on I/O error.
 *
 * Included from self/runtime.c via #include "native/exec_argv_sha256.c"
 * analogous to net.c / signal_flock.c. Pure libc; portable macOS/Linux.
 *
 * Rationale: exec(cmd)/exec_with_status(cmd) both route through
 * `/bin/sh -c`. Any command containing shell metacharacters (quotes,
 * `$`, backticks, heredocs) must be manually escaped. Three nexus tools
 * (tool/proposal_archive.hexa, drill_cycle_trigger.hexa,
 * dormancy_wake_tick.hexa) work around this by writing temporary script
 * files. exec_argv bypasses the shell entirely, removing the escape
 * burden on the call site.
 *
 * sha256 previously required shelling out to `shasum -a 256` or
 * `openssl dgst -sha256`, doubling the latency of anything that hashes
 * (inventory entries, manifests, cross-repo floor checks).
 */

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdint.h>
#include <unistd.h>
#include <fcntl.h>
#include <errno.h>
#include <sys/types.h>
#include <sys/wait.h>

/* ══════════════════════════════════════════════════════════════════
 * exec_argv — direct fork/execvp, no shell
 * ══════════════════════════════════════════════════════════════════ */

/* Internal: materialize argv_val into a heap-allocated NULL-terminated
 * char** suitable for execvp. Returns NULL on allocation failure or if
 * the array is empty. Caller must free both the array and its cells. */
static char** _hxa_materialize_argv(HexaVal argv_val, int* out_argc) {
    *out_argc = 0;
    if (!HX_IS_ARRAY(argv_val)) return NULL;
    int64_t n = (int64_t)HX_ARR_LEN(argv_val);
    if (n <= 0) return NULL;
    char** argv = (char**)calloc((size_t)n + 1, sizeof(char*));
    if (!argv) return NULL;
    for (int64_t i = 0; i < n; i++) {
        HexaVal el = hexa_array_get(argv_val, i);
        const char* s = HX_IS_STR(el) ? HX_STR(el) : "";
        if (!s) s = "";
        argv[i] = strdup(s);
        if (!argv[i]) {
            for (int64_t j = 0; j < i; j++) free(argv[j]);
            free(argv);
            return NULL;
        }
    }
    argv[n] = NULL;
    *out_argc = (int)n;
    return argv;
}

static void _hxa_free_argv(char** argv, int argc) {
    if (!argv) return;
    for (int i = 0; i < argc; i++) free(argv[i]);
    free(argv);
}

/* Shared core: fork, execvp, capture stdout, optionally return exit code. */
static HexaVal _hxa_exec_argv_core(HexaVal argv_val, int want_status) {
    int argc = 0;
    char** argv = _hxa_materialize_argv(argv_val, &argc);
    if (!argv || argc == 0) {
        if (want_status) {
            HexaVal arr = hexa_array_new();
            arr = hexa_array_push(arr, hexa_str(""));
            arr = hexa_array_push(arr, hexa_int(127));
            return arr;
        }
        return hexa_str("");
    }

    int pipefd[2];
    if (hxlcl_pipe(pipefd) < 0) {
        _hxa_free_argv(argv, argc);
        if (want_status) {
            HexaVal arr = hexa_array_new();
            arr = hexa_array_push(arr, hexa_str(""));
            arr = hexa_array_push(arr, hexa_int(127));
            return arr;
        }
        return hexa_str("");
    }

    // 2026-05-06 — POSIX fork buffer flush (parent stdio inherited by child)
    fflush(NULL);
    pid_t pid = hxlcl_fork();
    if (pid < 0) {
        hxlcl_close(pipefd[0]); hxlcl_close(pipefd[1]);
        _hxa_free_argv(argv, argc);
        if (want_status) {
            HexaVal arr = hexa_array_new();
            arr = hexa_array_push(arr, hexa_str(""));
            arr = hexa_array_push(arr, hexa_int(127));
            return arr;
        }
        return hexa_str("");
    }
    if (pid == 0) {
        /* child: stdout+stderr → pipe write end. Matches the
         * `exec(cmd)` behavior (popen merges stderr by default when
         * the caller appends `2>&1`; we default-merge here so the
         * migration from exec→exec_argv is stdout-compatible). */
        hxlcl_dup2(pipefd[1], 1);
        hxlcl_dup2(pipefd[1], 2);
        hxlcl_close(pipefd[0]);
        hxlcl_close(pipefd[1]);
        hxlcl_execvp(argv[0], argv);
        /* execvp failed */
        fprintf(stderr, "exec_argv: execvp %s: %s\n", argv[0], strerror(errno));
        _exit(127);
    }
    /* parent */
    hxlcl_close(pipefd[1]);
    _hxa_free_argv(argv, argc);

    size_t cap = 4096, total = 0;
    char* buf = (char*)malloc(cap);
    if (buf) buf[0] = '\0';
    char tmp[4096];
    for (;;) {
        ssize_t n = hxlcl_read(pipefd[0], tmp, sizeof(tmp));
        if (n < 0) { if (errno == EINTR) continue; break; }
        if (n == 0) break;
        if (buf) {
            while (total + (size_t)n + 1 > cap) {
                cap *= 2;
                char* nb = (char*)realloc(buf, cap);
                if (!nb) { free(buf); buf = NULL; break; }
                buf = nb;
            }
            if (buf) { memcpy(buf + total, tmp, (size_t)n); total += (size_t)n; buf[total] = '\0'; }
        }
    }
    hxlcl_close(pipefd[0]);

    int status = 0;
    (void)hxlcl_waitpid(pid, &status, 0);
    int exit_code;
    if (WIFEXITED(status))        exit_code = WEXITSTATUS(status);
    else if (WIFSIGNALED(status)) exit_code = 128 + WTERMSIG(status);
    else                          exit_code = -1;

    if (want_status) {
        HexaVal arr = hexa_array_new();
        arr = hexa_array_push(arr, buf ? hexa_str_own(buf) : hexa_str(""));
        arr = hexa_array_push(arr, hexa_int(exit_code));
        return arr;
    }
    return buf ? hexa_str_own(buf) : hexa_str("");
}

HexaVal hexa_exec_argv(HexaVal argv_val) {
    return _hxa_exec_argv_core(argv_val, 0);
}

HexaVal hexa_exec_argv_with_status(HexaVal argv_val) {
    return _hxa_exec_argv_core(argv_val, 1);
}

/* ══════════════════════════════════════════════════════════════════
 * sha256 — FIPS 180-4 reference implementation
 *
 * Pure-C; independent of OpenSSL / CommonCrypto / libsodium so the
 * hexa_interp binary stays dependency-free across macOS/Linux.
 * ══════════════════════════════════════════════════════════════════ */

typedef struct {
    uint32_t h[8];
    uint64_t bitlen;
    uint8_t  buf[64];
    uint32_t buflen;
} _hxa_sha256_ctx;

static const uint32_t _hxa_sha256_K[64] = {
    0x428a2f98,0x71374491,0xb5c0fbcf,0xe9b5dba5,0x3956c25b,0x59f111f1,0x923f82a4,0xab1c5ed5,
    0xd807aa98,0x12835b01,0x243185be,0x550c7dc3,0x72be5d74,0x80deb1fe,0x9bdc06a7,0xc19bf174,
    0xe49b69c1,0xefbe4786,0x0fc19dc6,0x240ca1cc,0x2de92c6f,0x4a7484aa,0x5cb0a9dc,0x76f988da,
    0x983e5152,0xa831c66d,0xb00327c8,0xbf597fc7,0xc6e00bf3,0xd5a79147,0x06ca6351,0x14292967,
    0x27b70a85,0x2e1b2138,0x4d2c6dfc,0x53380d13,0x650a7354,0x766a0abb,0x81c2c92e,0x92722c85,
    0xa2bfe8a1,0xa81a664b,0xc24b8b70,0xc76c51a3,0xd192e819,0xd6990624,0xf40e3585,0x106aa070,
    0x19a4c116,0x1e376c08,0x2748774c,0x34b0bcb5,0x391c0cb3,0x4ed8aa4a,0x5b9cca4f,0x682e6ff3,
    0x748f82ee,0x78a5636f,0x84c87814,0x8cc70208,0x90befffa,0xa4506ceb,0xbef9a3f7,0xc67178f2
};

#define _HXA_ROTR(x,n) (((x) >> (n)) | ((x) << (32 - (n))))

static void _hxa_sha256_init(_hxa_sha256_ctx* c) {
    c->h[0]=0x6a09e667; c->h[1]=0xbb67ae85; c->h[2]=0x3c6ef372; c->h[3]=0xa54ff53a;
    c->h[4]=0x510e527f; c->h[5]=0x9b05688c; c->h[6]=0x1f83d9ab; c->h[7]=0x5be0cd19;
    c->bitlen = 0;
    c->buflen = 0;
}

static void _hxa_sha256_transform(_hxa_sha256_ctx* c, const uint8_t* blk) {
    uint32_t w[64];
    for (int i = 0; i < 16; i++) {
        w[i] = ((uint32_t)blk[i*4] << 24) | ((uint32_t)blk[i*4+1] << 16)
             | ((uint32_t)blk[i*4+2] << 8) | (uint32_t)blk[i*4+3];
    }
    for (int i = 16; i < 64; i++) {
        uint32_t s0 = _HXA_ROTR(w[i-15],7) ^ _HXA_ROTR(w[i-15],18) ^ (w[i-15] >> 3);
        uint32_t s1 = _HXA_ROTR(w[i-2],17) ^ _HXA_ROTR(w[i-2],19) ^ (w[i-2] >> 10);
        w[i] = w[i-16] + s0 + w[i-7] + s1;
    }
    uint32_t a=c->h[0], b=c->h[1], d=c->h[2], e=c->h[3];
    uint32_t f=c->h[4], g=c->h[5], hh=c->h[6], ii=c->h[7];
    for (int i = 0; i < 64; i++) {
        uint32_t S1 = _HXA_ROTR(f,6) ^ _HXA_ROTR(f,11) ^ _HXA_ROTR(f,25);
        uint32_t ch = (f & g) ^ (~f & hh);
        uint32_t t1 = ii + S1 + ch + _hxa_sha256_K[i] + w[i];
        uint32_t S0 = _HXA_ROTR(a,2) ^ _HXA_ROTR(a,13) ^ _HXA_ROTR(a,22);
        uint32_t mj = (a & b) ^ (a & d) ^ (b & d);
        uint32_t t2 = S0 + mj;
        ii = hh; hh = g; g = f; f = e + t1;
        e = d; d = b; b = a; a = t1 + t2;
    }
    c->h[0]+=a; c->h[1]+=b; c->h[2]+=d; c->h[3]+=e;
    c->h[4]+=f; c->h[5]+=g; c->h[6]+=hh; c->h[7]+=ii;
}

static void _hxa_sha256_update(_hxa_sha256_ctx* c, const uint8_t* data, size_t len) {
    c->bitlen += (uint64_t)len * 8;
    while (len > 0) {
        size_t want = 64 - c->buflen;
        size_t take = len < want ? len : want;
        memcpy(c->buf + c->buflen, data, take);
        c->buflen += (uint32_t)take;
        data += take;
        len  -= take;
        if (c->buflen == 64) {
            _hxa_sha256_transform(c, c->buf);
            c->buflen = 0;
        }
    }
}

static void _hxa_sha256_final(_hxa_sha256_ctx* c, uint8_t out[32]) {
    uint64_t bitlen = c->bitlen;
    c->buf[c->buflen++] = 0x80;
    if (c->buflen > 56) {
        while (c->buflen < 64) c->buf[c->buflen++] = 0;
        _hxa_sha256_transform(c, c->buf);
        c->buflen = 0;
    }
    while (c->buflen < 56) c->buf[c->buflen++] = 0;
    for (int i = 7; i >= 0; i--) c->buf[c->buflen++] = (uint8_t)((bitlen >> (i*8)) & 0xff);
    _hxa_sha256_transform(c, c->buf);
    for (int i = 0; i < 8; i++) {
        out[i*4]   = (uint8_t)((c->h[i] >> 24) & 0xff);
        out[i*4+1] = (uint8_t)((c->h[i] >> 16) & 0xff);
        out[i*4+2] = (uint8_t)((c->h[i] >>  8) & 0xff);
        out[i*4+3] = (uint8_t)( c->h[i]        & 0xff);
    }
}

static char* _hxa_hex_encode(const uint8_t* bytes, size_t n) {
    static const char* hex = "0123456789abcdef";
    char* out = (char*)malloc(n * 2 + 1);
    if (!out) return NULL;
    for (size_t i = 0; i < n; i++) {
        out[i*2]   = hex[(bytes[i] >> 4) & 0xf];
        out[i*2+1] = hex[ bytes[i]       & 0xf];
    }
    out[n*2] = '\0';
    return out;
}

HexaVal hexa_sha256(HexaVal s_val) {
    if (!HX_IS_STR(s_val)) return hexa_str("");
    const char* s = HX_STR(s_val) ? HX_STR(s_val) : "";
    _hxa_sha256_ctx ctx;
    _hxa_sha256_init(&ctx);
    _hxa_sha256_update(&ctx, (const uint8_t*)s, strlen(s));
    uint8_t digest[32];
    _hxa_sha256_final(&ctx, digest);
    char* hex = _hxa_hex_encode(digest, 32);
    if (!hex) return hexa_str("");
    return hexa_str_own(hex);
}

HexaVal hexa_sha256_file(HexaVal path_val) {
    if (!HX_IS_STR(path_val)) return hexa_str("");
    const char* path = HX_STR(path_val);
    if (!path) return hexa_str("");
    int fd = hxlcl_open_sys(path, O_RDONLY);
    if (fd < 0) return hexa_str("");
    _hxa_sha256_ctx ctx;
    _hxa_sha256_init(&ctx);
    uint8_t buf[8192];
    for (;;) {
        ssize_t n = hxlcl_read(fd, buf, sizeof(buf));
        if (n < 0) { if (errno == EINTR) continue; hxlcl_close(fd); return hexa_str(""); }
        if (n == 0) break;
        _hxa_sha256_update(&ctx, buf, (size_t)n);
    }
    hxlcl_close(fd);
    uint8_t digest[32];
    _hxa_sha256_final(&ctx, digest);
    char* hex = _hxa_hex_encode(digest, 32);
    if (!hex) return hexa_str("");
    return hexa_str_own(hex);
}

/* ══════════════════════════════════════════════════════════════════
 * sha1 — FIPS 180-4 reference implementation
 *
 * Added for the RFC 6455 WebSocket Sec-WebSocket-Key handshake
 * (Sec-WebSocket-Accept == base64(sha1(key + magic-GUID))). SHA-1 is
 * cryptographically broken for collision resistance but RFC 6455 uses
 * it purely as a fixed challenge-response transform, not for security —
 * the spec mandates this exact construction. Pure-C, dependency-free,
 * mirrors the sha256 reference above.
 *
 *   hexa_sha1(s)        : HexaVal str → HexaVal str (40-char lowercase hex)
 *   hexa_sha1_bytes(s)  : HexaVal str → HexaVal str (raw 20-byte digest,
 *                         binary-safe via hexa_str_own_with_len so the
 *                         result can be fed straight into base64_encode)
 * ══════════════════════════════════════════════════════════════════ */

/* Binary-safe string constructor (defined in runtime_core.c); forward
 * decl so this translation unit can return raw digest bytes that carry
 * an explicit length (NUL-safe) for base64_encode to consume. */
HexaVal hexa_str_own_with_len(char* s, size_t len);

typedef struct {
    uint32_t h[5];
    uint64_t bitlen;
    uint8_t  buf[64];
    uint32_t buflen;
} _hxa_sha1_ctx;

#define _HXA_ROTL(x,n) (((x) << (n)) | ((x) >> (32 - (n))))

static void _hxa_sha1_init(_hxa_sha1_ctx* c) {
    c->h[0]=0x67452301; c->h[1]=0xEFCDAB89; c->h[2]=0x98BADCFE;
    c->h[3]=0x10325476; c->h[4]=0xC3D2E1F0;
    c->bitlen = 0;
    c->buflen = 0;
}

static void _hxa_sha1_transform(_hxa_sha1_ctx* c, const uint8_t* blk) {
    uint32_t w[80];
    for (int i = 0; i < 16; i++) {
        w[i] = ((uint32_t)blk[i*4] << 24) | ((uint32_t)blk[i*4+1] << 16)
             | ((uint32_t)blk[i*4+2] << 8) | (uint32_t)blk[i*4+3];
    }
    for (int i = 16; i < 80; i++) {
        w[i] = _HXA_ROTL(w[i-3] ^ w[i-8] ^ w[i-14] ^ w[i-16], 1);
    }
    uint32_t a=c->h[0], b=c->h[1], d=c->h[2], e=c->h[3], f=c->h[4];
    for (int i = 0; i < 80; i++) {
        uint32_t k, t;
        if (i < 20)      { t = (b & d) | (~b & e);            k = 0x5A827999; }
        else if (i < 40) { t = b ^ d ^ e;                     k = 0x6ED9EBA1; }
        else if (i < 60) { t = (b & d) | (b & e) | (d & e);   k = 0x8F1BBCDC; }
        else             { t = b ^ d ^ e;                     k = 0xCA62C1D6; }
        uint32_t tmp = _HXA_ROTL(a, 5) + t + f + k + w[i];
        f = e; e = d; d = _HXA_ROTL(b, 30); b = a; a = tmp;
    }
    c->h[0]+=a; c->h[1]+=b; c->h[2]+=d; c->h[3]+=e; c->h[4]+=f;
}

static void _hxa_sha1_update(_hxa_sha1_ctx* c, const uint8_t* data, size_t len) {
    c->bitlen += (uint64_t)len * 8;
    while (len > 0) {
        size_t want = 64 - c->buflen;
        size_t take = len < want ? len : want;
        memcpy(c->buf + c->buflen, data, take);
        c->buflen += (uint32_t)take;
        data += take;
        len  -= take;
        if (c->buflen == 64) {
            _hxa_sha1_transform(c, c->buf);
            c->buflen = 0;
        }
    }
}

static void _hxa_sha1_final(_hxa_sha1_ctx* c, uint8_t out[20]) {
    uint64_t bitlen = c->bitlen;
    c->buf[c->buflen++] = 0x80;
    if (c->buflen > 56) {
        while (c->buflen < 64) c->buf[c->buflen++] = 0;
        _hxa_sha1_transform(c, c->buf);
        c->buflen = 0;
    }
    while (c->buflen < 56) c->buf[c->buflen++] = 0;
    for (int i = 7; i >= 0; i--) c->buf[c->buflen++] = (uint8_t)((bitlen >> (i*8)) & 0xff);
    _hxa_sha1_transform(c, c->buf);
    for (int i = 0; i < 5; i++) {
        out[i*4]   = (uint8_t)((c->h[i] >> 24) & 0xff);
        out[i*4+1] = (uint8_t)((c->h[i] >> 16) & 0xff);
        out[i*4+2] = (uint8_t)((c->h[i] >>  8) & 0xff);
        out[i*4+3] = (uint8_t)( c->h[i]        & 0xff);
    }
}

/* sha1(s) — accepts the string's full byte length (HX_STRLEN), so a
 * binary-safe input (e.g. a digest) hashes correctly even with NULs. */
HexaVal hexa_sha1(HexaVal s_val) {
    if (!HX_IS_STR(s_val)) return hexa_str("");
    const char* s = HX_STR(s_val) ? HX_STR(s_val) : "";
    size_t n = HX_STR(s_val) ? (size_t)HX_STRLEN(s_val) : 0;
    _hxa_sha1_ctx ctx;
    _hxa_sha1_init(&ctx);
    _hxa_sha1_update(&ctx, (const uint8_t*)s, n);
    uint8_t digest[20];
    _hxa_sha1_final(&ctx, digest);
    char* hex = _hxa_hex_encode(digest, 20);
    if (!hex) return hexa_str("");
    return hexa_str_own(hex);
}

/* sha1_bytes(s) — raw 20-byte digest as a binary-safe hexa string.
 * Intended for base64_encode(sha1_bytes(key + magic)) in the RFC 6455
 * Sec-WebSocket-Accept computation. */
HexaVal hexa_sha1_bytes(HexaVal s_val) {
    if (!HX_IS_STR(s_val)) return hexa_str("");
    const char* s = HX_STR(s_val) ? HX_STR(s_val) : "";
    size_t n = HX_STR(s_val) ? (size_t)HX_STRLEN(s_val) : 0;
    _hxa_sha1_ctx ctx;
    _hxa_sha1_init(&ctx);
    _hxa_sha1_update(&ctx, (const uint8_t*)s, n);
    uint8_t digest[20];
    _hxa_sha1_final(&ctx, digest);
    return hexa_str_own_with_len((char*)digest, 20);
}

/* ── TAG_FN shim globals (bootstrap bridge) ──────────────────────
 * Same pattern as net.c / signal_flock.c. Interpreter path resolves
 * `exec_argv(...)` / `sha256(...)` through these shims until the
 * transpiler learns direct-lowering. After direct-lowering the
 * globals simply remain unused. */
HexaVal hx_exec_argv;
HexaVal hx_exec_argv_with_status;
HexaVal hx_sha256;
HexaVal hx_sha256_file;
HexaVal hx_sha1;
HexaVal hx_sha1_bytes;

static void _hexa_init_exec_sha_fn_shims(void) {
    hx_exec_argv             = hexa_fn_new((void*)hexa_exec_argv,             1);
    hx_exec_argv_with_status = hexa_fn_new((void*)hexa_exec_argv_with_status, 1);
    hx_sha256                = hexa_fn_new((void*)hexa_sha256,                1);
    hx_sha256_file           = hexa_fn_new((void*)hexa_sha256_file,           1);
    hx_sha1                  = hexa_fn_new((void*)hexa_sha1,                  1);
    hx_sha1_bytes            = hexa_fn_new((void*)hexa_sha1_bytes,            1);
}
/* amalgam END native/exec_argv_sha256.c */

/* ═══════════════════════════════════════════════════════════════════
 * persistent_pipe — ω-runtime-1 Phase A (2026-04-26)
 *
 * Handle-based bidirectional child-process API. Five new builtins:
 *   pipe_spawn(cmd) -> int
 *   pipe_send_line(h, payload) -> bool
 *   pipe_recv_line(h, timeout_ms) -> string
 *   pipe_close(h) -> bool
 *   pipe_alive(h) -> bool
 * Powers ω-audio-2 60× chain target (replaces _audio_worker_call.sh
 * 133-line bash shim with sub-ms send/recv via persistent fork).
 * ═══════════════════════════════════════════════════════════════════ */
/* amalgam BEGIN native/persistent_pipe.c */
/* self/native/persistent_pipe.c
 *
 * ω-runtime-1 Phase A — persistent-pipe primitive (2026-04-26).
 *
 * Five new builtins (handle-based bidirectional child-process API):
 *
 *   hexa_pipe_spawn(cmd)               : str        → int   handle id (≥0) or -1
 *   hexa_pipe_send_line(h, payload)    : int, str   → bool  true on full write
 *   hexa_pipe_recv_line(h, timeout_ms) : int, int   → str   line (\n trimmed) or ""
 *   hexa_pipe_close(h)                 : int        → bool  true on clean close
 *   hexa_pipe_alive(h)                 : int        → bool  child still running
 *
 * Maps onto the existing hexa_exec_capture (pipe+fork+execvp+dup2)
 * pattern from runtime.c:6010 — about 60% reusable. Difference: keeps
 * pipes open after hxlcl_fork() instead of draining-then-closing them, and
 * exposes the parent ends through a static handle table.
 *
 * Design doc: /Users/ghost/core/anima/state/omega_runtime_1_persistent_pipe_design.json
 *
 * Lifecycle:
 *   - Soft cap: min(RLIMIT_NOFILE/4, 64) concurrent live handles.
 *     Each handle eats 2 fds (stdin pipe write-end, stdout pipe read-end).
 *   - hxlcl_close(h): SIGTERM → 100ms grace → SIGKILL → waitpid → free slot.
 *   - atexit handler: SIGTERM all live, sleep 50ms, SIGKILL, hxlcl_waitpid(WNOHANG).
 *
 * v1 limitations (per design):
 *   - line-protocol-only on recv: response >PIPE_BUF (4KB darwin) risks deadlock
 *     for the worker if its newline-flush is delayed; the audio-worker NDJSON
 *     responses are <256B so this is safe for the immediate consumer.
 *   - stderr inherited (not separately captured); matches design.
 *   - synchronous per handle (one in-flight req); concurrency across handles is
 *     the user's problem.
 *
 * Included from self/runtime.c via #include "native/persistent_pipe.c"
 * analogous to net.c / signal_flock.c / exec_argv_sha256.c.
 */

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdint.h>
#include <unistd.h>
#include <fcntl.h>
#include <errno.h>
#include <signal.h>
#include <poll.h>
#include <time.h>
#include <sys/types.h>
#include <sys/wait.h>
#include <sys/resource.h>

/* ── handle table ───────────────────────────────────────────── */

typedef struct {
    pid_t  pid;          /* 0 = free slot */
    int    stdin_fd;     /* parent write-end → child stdin */
    int    stdout_fd;    /* parent read-end  ← child stdout */
    int    state;        /* 0=free, 1=live, 2=dead-pending-close */
    int    last_exit;    /* captured exit code (waitpid) */
} HexaChild;

#define HXP_MAX_HANDLES 64

static HexaChild g_pipe_table[HXP_MAX_HANDLES];
static int       g_pipe_table_inited = 0;
static int       g_pipe_atexit_installed = 0;

static long _hxp_now_ms(void) {
    struct timespec ts;
    hxlcl_clock_gettime(CLOCK_MONOTONIC, &ts);
    return (long)ts.tv_sec * 1000L + (long)(ts.tv_nsec / 1000000L);
}

static void _hxp_sleep_ms(int ms) {
    struct timespec ts;
    ts.tv_sec  = ms / 1000;
    ts.tv_nsec = (long)(ms % 1000) * 1000000L;
    hxlcl_nanosleep(&ts, NULL);
}

static void _hxp_atexit_cleanup(void) {
    for (int i = 0; i < HXP_MAX_HANDLES; i++) {
        HexaChild* c = &g_pipe_table[i];
        if (c->state == 1 && c->pid > 0) {
            if (c->stdin_fd  >= 0) { hxlcl_close(c->stdin_fd);  c->stdin_fd  = -1; }
            hxlcl_kill(c->pid, SIGTERM);
        }
    }
    /* short grace period for SIGTERM */
    _hxp_sleep_ms(50);
    for (int i = 0; i < HXP_MAX_HANDLES; i++) {
        HexaChild* c = &g_pipe_table[i];
        if (c->state == 1 && c->pid > 0) {
            hxlcl_kill(c->pid, SIGKILL);
            hxlcl_waitpid(c->pid, NULL, WNOHANG);
            if (c->stdout_fd >= 0) { hxlcl_close(c->stdout_fd); c->stdout_fd = -1; }
            c->state = 0;
        }
    }
}

static void _hxp_init_table(void) {
    if (g_pipe_table_inited) return;
    for (int i = 0; i < HXP_MAX_HANDLES; i++) {
        g_pipe_table[i].pid       = 0;
        g_pipe_table[i].stdin_fd  = -1;
        g_pipe_table[i].stdout_fd = -1;
        g_pipe_table[i].state     = 0;
        g_pipe_table[i].last_exit = 0;
    }
    g_pipe_table_inited = 1;
    if (!g_pipe_atexit_installed) {
        hxlcl_atexit(_hxp_atexit_cleanup);
        g_pipe_atexit_installed = 1;
    }
}

static int _hxp_max_handles(void) {
    /* soft cap = min(RLIMIT_NOFILE/4, HXP_MAX_HANDLES). */
    struct rlimit rl;
    int cap = HXP_MAX_HANDLES;
    if (hxlcl_getrlimit(RLIMIT_NOFILE, &rl) == 0 && rl.rlim_cur > 0) {
        int soft = (int)(rl.rlim_cur / 4);
        if (soft > 0 && soft < cap) cap = soft;
    }
    if (cap < 1) cap = 1;
    return cap;
}

static int _hxp_alloc_slot(void) {
    int cap = _hxp_max_handles();
    for (int i = 0; i < cap; i++) {
        if (g_pipe_table[i].state == 0 && g_pipe_table[i].pid == 0) return i;
    }
    return -1;
}

static HexaChild* _hxp_slot(int h) {
    if (h < 0 || h >= HXP_MAX_HANDLES) return NULL;
    return &g_pipe_table[h];
}

static HexaChild* _hxp_live(int h) {
    HexaChild* c = _hxp_slot(h);
    if (!c) return NULL;
    if (c->state != 1) return NULL;
    return c;
}

/* ── spawn ──────────────────────────────────────────────────── */

HexaVal hexa_pipe_spawn(HexaVal cmd_val) {
    _hxp_init_table();
    if (!HX_IS_STR(cmd_val) || !HX_STR(cmd_val)) return hexa_int(-1);
    const char* cmd = HX_STR(cmd_val);

    int slot = _hxp_alloc_slot();
    if (slot < 0) return hexa_int(-1);

    int in_pipe[2], out_pipe[2];
    if (hxlcl_pipe(in_pipe) != 0) return hexa_int(-1);
    if (hxlcl_pipe(out_pipe) != 0) {
        hxlcl_close(in_pipe[0]); hxlcl_close(in_pipe[1]);
        return hexa_int(-1);
    }

    // 2026-05-06 — POSIX fork buffer flush (parent stdio inherited by child)
    fflush(NULL);
    pid_t pid = hxlcl_fork();
    if (pid < 0) {
        hxlcl_close(in_pipe[0]);  hxlcl_close(in_pipe[1]);
        hxlcl_close(out_pipe[0]); hxlcl_close(out_pipe[1]);
        return hexa_int(-1);
    }
    if (pid == 0) {
        /* child */
        hxlcl_dup2(in_pipe[0],  0);
        hxlcl_dup2(out_pipe[1], 1);
        hxlcl_close(in_pipe[0]);  hxlcl_close(in_pipe[1]);
        hxlcl_close(out_pipe[0]); hxlcl_close(out_pipe[1]);
        hxlcl_execl("/bin/sh", "sh", "-c", cmd, (char*)NULL);
        _exit(127);
    }

    /* parent */
    hxlcl_close(in_pipe[0]);   /* parent doesn't read from stdin pipe */
    hxlcl_close(out_pipe[1]);  /* parent doesn't write to stdout pipe */

    /* Probe for early-exec failure: poll stdout pipe for EOF / waitpid
     * the child up to ~60ms total. If child died with non-zero exit
     * (typically 127 from /bin/sh: command not found), surface as -1.
     * This gives spawn() of a nonexistent command a clean failure path
     * (matches design "spawn returns -1 on error"). */
    int status = 0;
    pid_t r = 0;
    for (int probe = 0; probe < 6; probe++) {
        _hxp_sleep_ms(10);
        r = hxlcl_waitpid(pid, &status, WNOHANG);
        if (r == pid) break;
    }
    if (r == pid) {
        /* child already exited — likely exec failure */
        int ec = WIFEXITED(status) ? WEXITSTATUS(status)
              : (WIFSIGNALED(status) ? 128 + WTERMSIG(status) : -1);
        if (ec != 0) {
            /* non-zero exit during spawn-probe window → treat as failure.
             * Most commonly /bin/sh -c 'nonexistent_cmd' exits 127. */
            hxlcl_close(in_pipe[1]);
            hxlcl_close(out_pipe[0]);
            return hexa_int(-1);
        }
        /* child exited cleanly — keep the slot so caller can recv any
         * already-buffered output; record exit code. */
        HexaChild* c = &g_pipe_table[slot];
        c->pid = pid;
        c->stdin_fd = in_pipe[1];
        c->stdout_fd = out_pipe[0];
        c->state = 2; /* dead-pending-close */
        c->last_exit = ec;
        return hexa_int(slot);
    }

    HexaChild* c = &g_pipe_table[slot];
    c->pid = pid;
    c->stdin_fd = in_pipe[1];
    c->stdout_fd = out_pipe[0];
    c->state = 1;
    c->last_exit = 0;
    return hexa_int(slot);
}

/* ── send_line ──────────────────────────────────────────────── */

HexaVal hexa_pipe_send_line(HexaVal h_val, HexaVal payload_val) {
    _hxp_init_table();
    if (!HX_IS_INT(h_val)) return hexa_int(0);
    int h = (int)HX_INT(h_val);
    HexaChild* c = _hxp_live(h);
    if (!c) return hexa_int(0);
    if (c->stdin_fd < 0) return hexa_int(0);
    const char* p = HX_IS_STR(payload_val) && HX_STR(payload_val) ? HX_STR(payload_val) : "";
    size_t n = strlen(p);
    /* write payload then trailing '\n'. Tolerate short writes via loop. */
    size_t off = 0;
    while (off < n) {
        ssize_t w = hxlcl_write(c->stdin_fd, p + off, n - off);
        if (w < 0) {
            if (errno == EINTR) continue;
            c->state = 2;
            return hexa_int(0);
        }
        if (w == 0) { c->state = 2; return hexa_int(0); }
        off += (size_t)w;
    }
    const char nl = '\n';
    while (1) {
        ssize_t w = hxlcl_write(c->stdin_fd, &nl, 1);
        if (w == 1) break;
        if (w < 0) {
            if (errno == EINTR) continue;
            c->state = 2;
            return hexa_int(0);
        }
    }
    return hexa_int(1);
}

/* ── recv_line ──────────────────────────────────────────────── */

HexaVal hexa_pipe_recv_line(HexaVal h_val, HexaVal timeout_val) {
    _hxp_init_table();
    if (!HX_IS_INT(h_val)) return hexa_str("");
    int h = (int)HX_INT(h_val);
    HexaChild* c = _hxp_slot(h);
    if (!c) return hexa_str("");
    if (c->state == 0) return hexa_str("");
    if (c->stdout_fd < 0) return hexa_str("");

    long timeout_ms = HX_IS_INT(timeout_val) ? (long)HX_INT(timeout_val) : 5000;
    if (timeout_ms < 0) timeout_ms = 0;

    long t0 = _hxp_now_ms();
    size_t cap = 256, len = 0;
    char* buf = (char*)malloc(cap);
    if (!buf) return hexa_str("");

    while (1) {
        long elapsed = _hxp_now_ms() - t0;
        long remain = timeout_ms - elapsed;
        if (remain < 0) remain = 0;

        struct pollfd pfd;
        pfd.fd = c->stdout_fd;
        pfd.events = POLLIN;
        pfd.revents = 0;
        int pr = hxlcl_poll(&pfd, 1, (int)remain);
        if (pr == 0) {
            /* timeout — return whatever we accumulated (may be partial) */
            if (len == 0) { free(buf); return hexa_str(""); }
            buf[len] = '\0';
            return hexa_str_own(buf);
        }
        if (pr < 0) {
            if (errno == EINTR) continue;
            free(buf);
            return hexa_str("");
        }
        /* data ready (or EOF on hangup) — read 1 byte to avoid over-read past '\n' */
        char ch;
        ssize_t rd = hxlcl_read(c->stdout_fd, &ch, 1);
        if (rd == 0) {
            /* EOF — child closed stdout, likely exited */
            int status = 0;
            pid_t wr = hxlcl_waitpid(c->pid, &status, WNOHANG);
            if (wr == c->pid) {
                c->last_exit = WIFEXITED(status) ? WEXITSTATUS(status)
                              : (WIFSIGNALED(status) ? 128 + WTERMSIG(status) : -1);
                c->state = 2;
            }
            if (len == 0) { free(buf); return hexa_str(""); }
            buf[len] = '\0';
            return hexa_str_own(buf);
        }
        if (rd < 0) {
            if (errno == EINTR) continue;
            free(buf);
            return hexa_str("");
        }
        if (ch == '\n') {
            buf[len] = '\0';
            return hexa_str_own(buf);
        }
        if (len + 1 >= cap) {
            cap *= 2;
            char* nb = (char*)realloc(buf, cap);
            if (!nb) { free(buf); return hexa_str(""); }
            buf = nb;
        }
        buf[len++] = ch;
    }
}

/* ── close ──────────────────────────────────────────────────── */

HexaVal hexa_pipe_close(HexaVal h_val) {
    _hxp_init_table();
    if (!HX_IS_INT(h_val)) return hexa_int(0);
    int h = (int)HX_INT(h_val);
    HexaChild* c = _hxp_slot(h);
    if (!c) return hexa_int(0);
    if (c->state == 0) return hexa_int(0);

    if (c->stdin_fd  >= 0) { hxlcl_close(c->stdin_fd);  c->stdin_fd  = -1; }
    if (c->state == 1 && c->pid > 0) {
        hxlcl_kill(c->pid, SIGTERM);
        int reaped = 0;
        for (int i = 0; i < 10; i++) {
            int status = 0;
            pid_t r = hxlcl_waitpid(c->pid, &status, WNOHANG);
            if (r == c->pid) {
                c->last_exit = WIFEXITED(status) ? WEXITSTATUS(status)
                              : (WIFSIGNALED(status) ? 128 + WTERMSIG(status) : -1);
                reaped = 1;
                break;
            }
            _hxp_sleep_ms(10);
        }
        if (!reaped) {
            hxlcl_kill(c->pid, SIGKILL);
            int status = 0;
            hxlcl_waitpid(c->pid, &status, 0);
            c->last_exit = WIFEXITED(status) ? WEXITSTATUS(status)
                          : (WIFSIGNALED(status) ? 128 + WTERMSIG(status) : -1);
        }
    } else if (c->state == 2 && c->pid > 0) {
        /* child already dead, just reap if we haven't yet */
        int status = 0;
        hxlcl_waitpid(c->pid, &status, WNOHANG);
    }
    if (c->stdout_fd >= 0) { hxlcl_close(c->stdout_fd); c->stdout_fd = -1; }
    c->state = 0;
    c->pid = 0;
    return hexa_int(1);
}

/* ── alive ──────────────────────────────────────────────────── */

HexaVal hexa_pipe_alive(HexaVal h_val) {
    _hxp_init_table();
    if (!HX_IS_INT(h_val)) return hexa_int(0);
    int h = (int)HX_INT(h_val);
    HexaChild* c = _hxp_slot(h);
    if (!c) return hexa_int(0);
    if (c->state != 1) return hexa_int(0);
    if (c->pid <= 0) return hexa_int(0);
    /* Reap if child has exited (non-blocking). */
    int status = 0;
    pid_t r = hxlcl_waitpid(c->pid, &status, WNOHANG);
    if (r == c->pid) {
        c->last_exit = WIFEXITED(status) ? WEXITSTATUS(status)
                      : (WIFSIGNALED(status) ? 128 + WTERMSIG(status) : -1);
        c->state = 2;
        return hexa_int(0);
    }
    /* Probe with hxlcl_kill(pid, 0) — distinguishes alive vs unreachable. */
    if (hxlcl_kill(c->pid, 0) != 0) {
        c->state = 2;
        return hexa_int(0);
    }
    return hexa_int(1);
}

