int main(int argc, char** argv) {
    if (argc < 3) {
        printf("hexa-cc: HEXA self-hosted compiler\nUsage: hexa-cc <input.hexa> <output.c>\n");
        return 1;
    }
    hexa_set_args(argc, argv);
    _lexer_init(argc, argv);
    _parser_init(argc, argv);
    _codegen_init(argc, argv);
    HexaVal src = rt_read_file(hexa_str(argv[1]));
    HexaVal tokens = tokenize(src);
    /* PROBE r10-18d: thread source text into parser so parse errors can
     * render rustc/clang-style source snippet + caret pointer. */
    p_set_source(src);
    HexaVal ast = parse(tokens);
    /* PROBE r14 #453 wiring: opt-in type_check pass via HEXA_TYPECHECK env.
     * Default off — corpus emits ~1322 warnings (immutable-let + non-exhaustive
     * match) which would flood normal builds. `hexa typecheck` sets the env. */
    if (getenv("HEXA_TYPECHECK") != NULL) {
        _type_checker_init(argc, argv);
        type_check_and_emit(ast);
    }
    HexaVal c_code = codegen_full(ast);
    /* F05 (2026-05-06): free AST+tokens before write to drop peak RSS. */
    if (HX_IS_ARRAY(ast)) hexa_array_free(ast);
    if (HX_IS_ARRAY(tokens)) hexa_array_free(tokens);
    hexa_arena_reset();
    rt_write_file(hexa_str(argv[2]), c_code);
    printf("OK: %s\n", argv[2]);
    return 0;
}
